INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (1, 22, 'Áo tanktop Pickleball Driveshot Essentials', 'ao-tanktop-pickleball-driveshot-essentials', 'Bề mặt vải mượt, chắc tay nhưng vẫn linh hoạt khi vận động; polyester tái chế giúp áo bền bỉ và giữ phom dáng ổn định', '<h2 style="text-align: center;">Áo Tanktop Pickleball Driveshot Essentials - Giải Pháp Tối Ưu Cho Những Set Đấu Đầy Năng Lượng</h2><p>Trong nhịp sống vận động hiện đại, chiếc áo tanktop Pickleball Driveshot Essentials xuất hiện như một sự lựa chọn <a href="https://www.coolmate.me/collection/ao-singlet-nu" target="_blank" rel="noopener">áo singlet nữ</a> tinh tế dành riêng cho phái đẹp yêu thích các bộ môn dùng vợt. Điểm đáng giá nhất của sản phẩm nằm ở chất liệu <a href="https://www.coolmate.me/blog/vai-recycle-la-gi-1668" target="_blank" rel="noopener">vải recycle</a> với tỷ lệ 84% <a href="https://www.coolmate.me/blog/recycled-polyester-4391" target="_blank" rel="noopener">Recycled Polyester</a> kết hợp cùng 16% <a href="https://www.coolmate.me/blog/spandex-la-gi" target="_blank" rel="noopener">Spandex</a>. Sự pha trộn này không chỉ thể hiện tinh thần thời trang bền vững mà còn mang lại bề mặt vải Jersey mịn màng, co giãn đa chiều, giúp nàng thoải mái thực hiện mọi cú đánh Driveshot quyết đoán. <a href="https://www.coolmate.me/blog/cong-nghe-exdry-4439" target="_blank" rel="noopener">Công nghệ Ex-Dry</a> được tích hợp giúp đẩy nhanh quá trình thoát hơi ẩm, giữ cho cơ thể luôn trong trạng thái khô ráo và nhẹ nhàng ngay cả khi cường độ tập luyện tăng cao. Khi khoác lên mình chiếc <a href="https://www.coolmate.me/collection/ao-nu" target="_blank" rel="noopener">áo nữ</a> này, bạn sẽ cảm nhận rõ sự khác biệt từ cảm giác mát tay đến sự linh hoạt tối đa trong từng chuyển động. Đây thực sự là mảnh ghép <a href="https://www.coolmate.me/collection/pickleball-tennis-cho-nu" target="_blank" rel="noopener">quần áo pickleball nữ</a> hoàn hảo cho tủ đồ tập chuyên nghiệp của bạn.</p><h3>Thiết kế Slim fit tôn dáng tích hợp bra tiện lợi</h3><p>Sản phẩm <a href="https://www.coolmate.me/collection/do-nu" target="_blank" rel="noopener">đồ nữ</a> sở hữu form dáng <a href="https://www.coolmate.me/blog/slim-fit-la-gi-cach-dien-ao-thun-slim-fit-ton-body-471" target="_blank" rel="noopener">Slim fit</a> ôm gọn cơ thể, giúp tôn lên những đường nét năng động mà không gây cảm giác gò bó hay khó chịu nhờ độ đàn hồi vượt trội của sợi Spandex.</p><ul><li><p>Thiết kế sát nách giúp giải phóng hoàn toàn vùng vai, tạo sự linh hoạt tuyệt đối cho các cử động tay khi chơi bóng.</p></li><li><p>Tích hợp sẵn lớp lót bra liền áo cực kỳ tiện lợi, giúp nàng tự tin vận động mà không cần lo lắng về việc phối hợp nội y bên trong.</p></li><li><p>Phần cổ tròn được viền màu Colorblock tinh tế, tạo điểm nhấn phong cách và giữ cho form dáng cổ luôn bền bỉ qua thời gian.</p></li><li><p>Công nghệ may phẳng (Flat-lock) giúp giảm thiểu ma sát giữa vải và da, ngăn ngừa tình trạng kích ứng khi tập luyện lâu.</p></li></ul><p><strong>Xem thêm:</strong> <a href="https://www.coolmate.me/blog/bi-quyet-chon-size-ao-thun-nu-chuan-nhu-may-do-5680" target="_blank" rel="noopener">Bí quyết chọn size áo thun nữ chuẩn như may đo</a></p><h3>Linh hoạt phong cách từ sân đấu ra phố thị</h3><p>Không chỉ dành riêng cho Pickleball, chiếc áo tanktop này còn chứng minh được tính đa năng đáng kinh ngạc, phù hợp với nhiều hoạt động khác nhau trong ngày của phái đẹp:</p><ul><li><p>Đồng hành lý tưởng trong các buổi tập Tennis, cầu lông hoặc các môn thể thao vận động cường độ vừa.</p></li><li><p>Dễ dàng phối cùng <a href="https://www.coolmate.me/collection/vay-dam-nu" target="_blank" rel="noopener">váy thể thao</a> hoặc <a href="https://www.coolmate.me/collection/quan-legging" target="_blank" rel="noopener">quần legging</a> cho những buổi tập Gym, Yoga hay chạy bộ tại công viên.</p></li></ul>', '{"Phù hợp": "Hoạt động tập luyện Pickleball & mặc hàng ngày", "Tính năng": "Thấm hút và co giãn  Lót liền áo", "Bảo quản": "Giặt máy nhẹ - Sấy ở mức nhiệt thấp  Không dùng chất tẩy - Không giặt khô", "Công nghệ": "Ex-Dry", "Kiểu dáng": "Slim fit  Mẫu cao 1m65, nặng 55kg, 84-68-94(cm) - Size S", "Chất liệu": "84% Recycled Polyester 16% Spandex Jersey"}', 279000.00, 238000.00, true, null, '2026-06-27 08:12:51', '2026-06-27 08:12:51');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (2, 26, 'Quần Legging 7/8 CoolFlex Light Support', 'quan-legging-78-coolflex-light-support', 'Vải siêu nhẹ, co giãn 4 chiều, mềm mại, thoáng khí, hỗ trợ vận động và giảm tích tụ nhiệt', '<p><a href="https://www.coolmate.me/collection/quan-legging-mac-hang-ngay" target="_blank" rel="noopener">Quần Legging 7/8 CoolFlex Light Support</a> là lựa chọn hoàn hảo cho những cô nàng yêu thích sự thoải mái và linh hoạt trong các hoạt động nhẹ nhàng hàng ngày. Với chất liệu vải chính 69% Nylon và 31% <a href="https://www.coolmate.me/post/spandex-la-gi" target="_blank" rel="noopener">Spandex</a>, kết hợp cùng vải lót 88% <a href="https://www.coolmate.me/post/vai-polyester-la-gi" target="_blank" rel="noopener">Polyester </a>và 12% Spandex, chiếc <a href="https://www.coolmate.me/collection/quan-dai-nu" target="_blank" rel="noopener" class="in-cell-link">quần dài nữ</a> này mang lại cảm giác mềm mại, co giãn 4 chiều và khả năng thoáng khí tuyệt vời. Công nghệ CoolFlex giúp vải luôn nhẹ nhàng, giảm tích tụ nhiệt, tạo cảm giác dễ chịu ngay cả khi bạn vận động.</p><p style="text-align: justify;"><strong>&gt;&gt; Xem thêm: </strong><a href="https://www.coolmate.me/post/kham-pha-cong-nghe-vai-coolflex-cooldry-doc-quyen-moi-cua-coolmate-5157" target="_blank" rel="noopener">Khám Phá Công Nghệ Vải CoolFlex &amp; CoolDry Độc Quyền Mới Của Coolmate</a></p><h2 style="text-align: justify;">Thiết Kế Tôn Dáng &amp; Đa Năng</h2><p style="text-align: justify;">Quần có phom dáng 7/8 ôm trọn cơ thể, tạo hiệu ứng thon gọn và tôn lên đường cong quyến rũ. Phần cạp quần được thiết kế vừa vặn, đảm bảo sự chắc chắn mà không gây cấn hay khó chịu. Chiếc quần legging này rất phù hợp cho các hoạt động như Yoga, Pilates, Aerobic, hoặc đơn giản là phối cùng áo thun, sweater để tạo nên phong cách năng động, trẻ trung cho nàng.</p><p><strong>&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/cach-chon-quan-legging-nu-theo-dang-nguoi-5483" target="_blank" rel="noopener">Cách chọn quần legging nữ theo dáng người - Bí quyết tôn dáng, thoải mái vận động</a></p><h2 style="text-align: justify;">Hỗ Trợ Vận Động Nhẹ &amp; Phong Cách Thời Trang</h2><p style="text-align: justify;">Chiếc quần legging 7/8 CoolFlex Light Support mang đến sự hỗ trợ nhẹ nhàng, lý tưởng cho các hoạt động:</p><ul><li><p><strong>Yoga &amp; Pilates:</strong> Cảm giác mềm mại, co giãn và thoáng khí giúp bạn tập trung hoàn toàn vào từng chuyển động.</p></li><li><p><strong>Aerobic &amp; Cardio nhẹ:</strong> Hỗ trợ vận động linh hoạt, giảm tích tụ nhiệt, giữ cơ thể luôn khô ráo và dễ chịu.</p></li><li><p><strong>Mặc hàng ngày:</strong> Dễ dàng phối hợp cùng trang phục yêu thích để tạo nên phong cách năng động, thoải mái cho mọi tình huống.</p></li></ul>', '{"Phù hợp": "Yoga & Pilates, Aerobic, mặc hàng ngày  Các hoạt động cường độ nhẹ", "Tính năng": "Có túi đựng hai bên tiện lợi", "Bảo quản": "Giặt máy chế độ nhẹ - Không dùng chất tẩy  Phơi mát, tránh nhiệt cao", "Công nghệ": "CoolFlex", "Kiểu dáng": " 7/8 Leggings - Ôm trọn cơ thể  Mẫu cao 1m69, nặng 52kg, số đo: 76-60-91(cm) - Size S", "Chất liệu": "Vải chính: 69% Nylon6 31% Spandex  Vải lót: 88% Polyester 12% Spandex"}', 459000.00, 367000.00, true, null, '2026-06-28 07:48:45', '2026-06-28 07:48:45');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (3, 6, 'Polo thể thao Promax Flexline Clash', 'polo-the-thao-promax-flexline-clash', 'Vải Promesh dạng ô vuông có cấu trúc lưới thông thoáng, hỗ trợ tối ưu việc lưu thông không khí, bề mặt vải mịn, ít nhăn', '<h2 style="text-align: center;">Polo thể thao Promax Flexline Active - Tối ưu cho vận động, thoải mái suốt ngày dài</h2><p>Trải nghiệm sự khác biệt trong từng chuyển động với Áo Polo thể thao Promax Flexline Active, một thiết kế đột phá dành riêng cho những chàng trai yêu thích vận động. Không chỉ là một chiếc <a href="https://www.coolmate.me/collection/ao-polo-nam-choi-the-thao">áo polo thể thao nam</a> chuyên dụng, đây còn là mảnh ghép hoàn hảo cho tủ đồ <a href="https://www.coolmate.me/collection/ao-nam">áo nam</a> đa năng của bạn. Sản phẩm được dệt từ 100% sợi Polyester, ứng dụng cấu trúc dệt Promesh độc đáo tạo ra hàng ngàn lỗ thoáng khí siêu nhỏ. Đặc biệt, công nghệ Ex-Dry trứ danh giúp thấm hút mồ hôi và làm khô nhanh chóng, vượt trội hơn hẳn các mẫu <a href="https://www.coolmate.me/collection/ao-polo-nam">áo polo nam</a> thông thường. Cảm giác bạn nhận được là sự nhẹ nhàng, thoáng mát và tự tin tuyệt đối, dù đang ở phòng gym hay tham gia các hoạt động ngoài trời.</p><h3>Thiết kế Regular Fit tôn dáng, linh hoạt</h3><p>Áo sở hữu kiểu dáng <a href="https://www.coolmate.me/post/regular-fit-la-gi">Regular fit</a> hiện đại, vừa vặn khéo léo với cơ thể nhưng vẫn đảm bảo không gian đủ rộng để bạn tự do thực hiện mọi động tác một cách linh hoạt nhất.</p><ul><li><p><strong>Điểm nhấn độc đáo:</strong> Đường line phối màu tương phản chạy từ vai xuống cánh tay, tạo phong cách khỏe khoắn, năng động.</p></li><li><p><strong>Cổ áo và nút cài:</strong> Cổ gập classic cùng hàng nút cài gọn gàng, giữ form dáng lịch sự.</p></li><li><p><strong>Logo tinh tế:</strong> Logo Coolmate được in chắc chắn trên ngực, khẳng định chất lượng thương hiệu.</p></li></ul><blockquote><p>Xem thêm: <a href="https://www.coolmate.me/blog/size-ao-polo-nam">Bảng chọn size áo polo nam chuẩn đẹp được áp dụng nhiều nhất hiện nay</a></p></blockquote><h3>Năng động trong mọi hoàn cảnh sử dụng</h3><p>Nhờ sự kết hợp giữa thiết kế thông minh và chất liệu ưu việt, chiếc áo này là lựa chọn lý tưởng cho nhiều mục đích:</p><ul><li><p>Tập luyện thể thao cường độ cao như gym, chạy bộ, tennis.</p></li><li><p>Tham gia các hoạt động dã ngoại, du lịch cuối tuần.</p></li><li><p>Diện hàng ngày khi đi cà phê, dạo phố cùng bạn bè.</p></li></ul><blockquote><p>Xem thêm: <a href="https://www.coolmate.me/post/phoi-do-voi-ao-polo-nam">10+ bí quyết phối đồ với áo polo nam cực chất</a></p></blockquote><p>Để có một set đồ hoàn chỉnh, bạn có thể kết hợp chiếc <a href="https://www.coolmate.me/collection/ao-nam-choi-the-thao">áo thể thao nam</a> này cùng một chiếc <a href="https://www.coolmate.me/collection/quan-short-nam">quần short nam</a> để tạo nên bộ <a href="https://www.coolmate.me/collection/coolmate-activewear">đồ thể thao</a> tràn đầy năng lượng.</p><h3>Bí Quyết Giữ Sản Phẩm Bền Đẹp</h3><p>Để sản phẩm luôn giữ được form dáng và tính năng vượt trội, hãy tuân thủ những hướng dẫn bảo quản đơn giản sau:</p><ul><li><p>Ưu tiên giặt máy ở chế độ nhẹ để bảo vệ cấu trúc vải.</p></li><li><p>Sấy khô ở nhiệt độ thấp hoặc phơi trong bóng râm, tránh ánh nắng gắt trực tiếp.</p></li><li><p>Tuyệt đối không sử dụng thuốc tẩy hay các chất giặt có độ tẩy rửa mạnh.</p></li></ul><p>Để chiếc áo của bạn luôn như mới, hãy tham khảo thêm những <a href="https://www.coolmate.me/blog/cach-giat-ao-polo-nam">mẹo giặt áo polo nam đúng cách</a> từ Coolmate.</p>', '{"Phù hợp": "Tập luyện thể thao và hàng ngày", "Tính năng": "Nhanh khô và thấm hút", "Bảo quản": "Giặt máy nhẹ - Sấy ở mức nhiệt thấp. Không dùng chất tẩy - Không giặt khô", "Công nghệ": "Ex-Dry", "Kiểu dáng": "Regular fit", "Chất liệu": "100% Polyester"}', 279000.00, 238000.00, true, null, '2026-06-28 08:04:57', '2026-06-28 08:04:57');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (4, 4, 'Áo Polo Thêu Logo Tròn', 'ao-polo-theu-logo-tron', 'Phù hợp mặc trong nhiều hoạt động bao gồm tập luyện các môn thểthao và mặc hàng ngày', '<h2 style="text-align: center;">Quần Shorts thể thao Promax Flexline Active  - Tự tin vận động, khô thoáng tức thì</h2><p>Đây không chỉ là một chiếc <a href="https://www.coolmate.me/collection/quan-nam-choi-the-thao" target="_blank" rel="noopener">quần thể thao nam</a> hiệu suất cao, mà còn là một item đa năng trong tủ đồ <a href="https://www.coolmate.me/collection/quan-nam" target="_blank" rel="noopener">quần nam</a> của bạn, sẵn sàng cho mọi hoạt động. Sản phẩm được dệt từ 100% sợi <a href="https://www.coolmate.me/post/vai-polyester-la-gi" target="_blank" rel="noopener">Polyester</a> cao cấp, kết hợp công nghệ dệt Promesh cấu trúc lưới ô vuông và công nghệ Ex-Dry độc quyền. Sự kết hợp này tạo ra một bề mặt vải siêu thoáng khí, giúp mồ hôi và hơi ẩm bay hơi nhanh chóng, đồng thời chất vải còn mềm mịn và chống nhăn hiệu quả. Cảm giác mặc trên người sẽ luôn khô ráo, nhẹ nhàng, giúp bạn hoàn toàn tập trung vào từng chuyển động.</p><h2>Thiết kế Regular Fit và phối màu đầy năng lượng</h2><p>Đây là chiếc <a href="https://www.coolmate.me/collection/quan-short-nam" target="_blank" rel="noopener">quần short nam</a> được thiết kế với form dáng <a href="https://www.coolmate.me/post/regular-fit-la-gi-395" target="_blank" rel="noopener">Regular Fit</a> vừa vặn, đảm bảo sự thoải mái tối đa và không gian cho mọi vận động từ đơn giản đến phức tạp, giúp bạn luôn cảm thấy tự tin.</p><ul><li><p><strong>Thiết kế phối màu:</strong> Các mảng màu đỏ và trắng được phối cắt xéo dọc bên hông trên nền <a href="https://www.coolmate.me/collection/quan-short-nam-den" target="_blank" rel="noopener">quần short nam đen</a>, tạo nên một tổng thể mạnh mẽ, khỏe khoắn và đầy tinh thần thể thao.</p></li><li><p><strong>Tiện ích:</strong> Quần có hai túi hông sâu, tiện lợi để đựng các vật dụng cần thiết. Lưng thun co giãn tốt, ôm vừa vặn cơ thể.</p></li></ul><p><em>Người mẫu trong ảnh cao 1m80, nặng 75kg và đang mặc quần size L.</em></p><p><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/cach-chon-quan-short-nam" target="_blank" rel="noopener">Cách Chọn Quần Short Nam Chuẩn Dáng, Hợp Hoàn Cảnh Trong Năm 2025</a></p><h2>Hoàn hảo cho mọi hoạt động thể chất</h2><p>Với thiết kế ấn tượng và tính năng vượt trội, chiếc quần này là lựa chọn lý tưởng để nâng tầm bộ sưu tập <a href="https://www.coolmate.me/collection/coolmate-activewear" target="_blank" rel="noopener">đồ thể thao</a> của bạn.</p><ul><li><p>Tập luyện đa môn: Phù hợp cho các hoạt động như chạy bộ, tập gym, chơi bóng rổ, bóng đá...</p></li><li><p>Trang phục hàng ngày: Dễ dàng kết hợp với áo thun, áo ba lỗ để tạo nên set đồ năng động dạo phố.</p></li><li><p>Hoạt động cổ vũ: Là trang phục hoàn hảo để thể hiện tinh thần yêu nước trong các sự kiện thể thao.</p></li></ul><h2>Bí Quyết Giữ Sản Phẩm Bền Đẹp</h2><p>Để chiếc quần short luôn giữ được vẻ ngoài và tính năng tốt nhất, bạn hãy chú ý:</p><ul><li><p>Giặt máy ở chế độ nhẹ nhàng, sử dụng nước ở nhiệt độ thường để bảo vệ cấu trúc vải.</p></li><li><p>Phơi ở nơi thoáng mát, tránh ánh nắng mặt trời trực tiếp để giữ màu sắc bền lâu.</p></li><li><p>Không sử dụng chất tẩy rửa mạnh và không giặt khô.</p></li></ul>', '{"Phù hợp": "Luyện tập thể dục thể thao", "Tính năng": "Thấm hút và nhanh khô", "Bảo quản": "Giặt máy nhẹ - Sấy ở mức nhiệt thấp. Không dùng chất tẩy - Không giặt khô", "Công nghệ": "Ex-Dry", "Kiểu dáng": "Tank", "Chất liệu": "100% Polyester"}', 345000.00, 209000.00, true, null, '2026-06-28 09:09:48', '2026-06-28 09:09:48');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (5, 6, 'Polo thể thao nam Quick Dry Active', 'polo-the-thao-nam-quick-dry-active', 'Thiết kế cổ đứng gia cố tape kết hợp trụ nút tối giản giúp giữ phom cổ ổn định, tăng độ bền và dễ điều chỉnh độ thoáng', '<h2 style="text-align: center;">Polo thể thao nam Quick Dry Active - Tối ưu hiệu suất vận động</h2><p style="text-align: justify;">Nếu bạn đang tìm kiếm một chiếc <a href="https://www.coolmate.me/collection/ao-polo-nam-choi-the-thao" target="_blank" rel="noopener">áo polo thể thao</a> đa năng, vừa đủ lịch sự để mặc đi làm nhưng vẫn đáp ứng tốt các bài tập cường độ cao, thì phiên bản Quick Dry Active là lựa chọn <a href="https://www.coolmate.me/collection/ao-nam" target="_blank" rel="noopener">áo nam</a> không thể bỏ qua. Sự khác biệt nằm ở chất liệu vải kết hợp giữa 93% CD Polyester và 7% <a href="https://www.coolmate.me/blog/spandex-la-gi" target="_blank" rel="noopener">Spandex</a>. Dòng sợi CD Polyester không chỉ mang lại hiệu ứng màu sắc độc đáo mà còn giữ trọn vẹn đặc tính siêu nhẹ và bền bỉ. Cảm giác mặc thực tế là sự nhẹ tênh và khô thoáng đáng kinh ngạc. Nhờ cơ chế thấm hút mồ hôi và bốc hơi nhanh (<a href="https://www.coolmate.me/blog/cong-nghe-quick-dry-4373" target="_blank" rel="noopener">Quick Dry</a>), chiếc <a href="https://www.coolmate.me/collection/ao-polo-na" target="_blank" rel="noopener">áo polo nam</a> giúp điều hòa thân nhiệt hiệu quả, hạn chế tối đa cảm giác bết dính khó chịu khi cơ thể ra nhiều mồ hôi. Độ co giãn tốt từ Spandex hỗ trợ bạn thực hiện mọi động tác xoay người, vung tay một cách linh hoạt nhất.</p><h3 style="text-align: justify;">Thiết kế cổ đứng tinh gọn và hiện đại</h3><p style="text-align: justify;">Sản phẩm được thiết kế theo phom dáng <a href="https://www.coolmate.me/blog/regular-fit-la-gi-395" target="_blank" rel="noopener">Regular Fit</a>, có độ suông vừa phải, không quá ôm sát như <a href="https://www.coolmate.me/blog/slim-fit-la-gi-cach-dien-ao-thun-slim-fit-ton-body-471" target="_blank" rel="noopener">Slim fit</a> nhưng cũng không quá rộng, phù hợp với đại đa số vóc dáng nam giới Việt. Kiểu dáng này giúp che khuyết điểm vùng bụng cực tốt trong khi vẫn giữ được vẻ ngoài gọn gàng.</p><ul><li><p>Cổ áo: Thiết kế cổ đứng được gia cố bằng đường tape chắc chắn bên trong, giúp cổ áo luôn đứng form, không bị đổ hay nhăn nhúm sau khi giặt.</p></li><li><p>Chi tiết: Trụ nút tối giản và các đường may tại điểm tiếp xúc được hoàn thiện kỹ lưỡng để giảm ma sát lên da.</p></li></ul><p style="text-align: justify;">Xem thêm: <a href="https://www.coolmate.me/blog/size-ao-polo-nam" target="_blank" rel="noopener">Bảng chọn size áo polo nam chuẩn đẹp được áp dụng nhiều nhất hiện nay</a></p><h3 style="text-align: justify;">Linh hoạt từ phòng tập ra phố</h3><p style="text-align: justify;">Với thiết kế tối giản, chiếc <a href="https://www.coolmate.me/collection/ao-nam-choi-the-thao" target="_blank" rel="noopener">áo thể thao nam</a> này xóa nhòa ranh giới giữa đồ tập và đồ mặc hàng ngày, mang lại tính ứng dụng cực cao cho người mặc:</p><ul><li><p>Tập luyện thể thao: Chạy bộ, Gym, Tennis hay các hoạt động ngoài trời cần sự thoáng khí.</p></li><li><p>Mặc hàng ngày: Phối cùng <a href="https://www.coolmate.me/collection/quan-short-nam" target="_blank" rel="noopener">quần short nam</a> hoặc <a href="https://www.coolmate.me/collection/quan-kaki-nam" target="_blank" rel="noopener">quần kaki</a> để đi cafe, đi làm trong môi trường năng động.</p></li></ul><p style="text-align: justify;">Xem thêm: <a href="https://www.coolmate.me/blog/phoi-do-voi-ao-polo-nam" target="_blank" rel="noopener">10+ bí quyết phối đồ với áo polo nam cực chất</a></p><h3 style="text-align: justify;">Bí quyết giữ sản phẩm bền đẹp</h3><p style="text-align: justify;">Để chiếc áo luôn khô thoáng, bền form và phát huy tối đa công nghệ Exdry, bạn nên tuân thủ những nguyên tắc giặt giũ sau:</p><ul><li><p>Nên giặt ngay sau khi sử dụng để tránh mồ hôi và vi khuẩn tích tụ gây mùi hoặc ố vải.</p></li><li><p>Không sử dụng nước xả vải vì sẽ làm mất tính năng thấm hút đặc trưng của dòng <a href="https://www.coolmate.me/collection/do-the-thao" target="_blank" rel="noopener">đồ thể thao</a>.</p></li><li><p>Giặt máy ở chế độ nhẹ với nước lạnh, lộn trái áo khi giặt để bảo vệ bề mặt vải CD Polyester.</p></li></ul><p style="text-align: justify;">Xem thêm: <a href="https://www.coolmate.me/blog/cach-giat-ao-polo-nam" target="_blank" rel="noopener">Mẹo giặt áo polo nam đúng cách giúp áo bền đẹp theo thời gian</a></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 299000.00, 255000.00, true, null, '2026-06-28 15:57:12', '2026-06-28 16:00:55');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (6, 6, 'Áo Polo Pickleball nam Zero Mark', 'ao-polo-pickleball-nam-zero-mark', 'Áo Polo Nam Thể Thao Promax-S1 sở hữu kiểu dáng Regular Fit, mang đến sự vừa vặn lý tưởng, không quá ôm sát cũng không quá rộng, đảm bảo sự thoải mái tối ưu cho mọi cử động. Thiết kế này là điểm nhấn trong quần áo thể thao, phù hợp với nhiều vóc dáng nam giới trong các hoạt động thể thao đa dạng.', '<p></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 459000.00, 391000.00, true, null, '2026-06-28 16:07:41', '2026-06-28 16:07:41');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (7, 6, 'Áo Polo Nam Thể Thao Promax-S1', 'ao-polo-nam-the-thao-promax-s1', 'Polo Thoáng khí', '<h2 style="text-align: justify;">Áo Polo Nam Thể Thao Promax-S1 - Khô Thoáng Tối Ưu, Hiệu Suất Đỉnh Cao</h2><p style="text-align: justify;">Áo Polo Nam Thể Thao Promax-S1 là sự kết hợp hoàn hảo giữa thiết kế thanh lịch và công nghệ thể thao tiên tiến, một lựa chọn không thể thiếu trong tủ đồ <a href="https://www.coolmate.me/collection/ao-nam" target="_blank" rel="noopener">áo nam</a> hiện đại. Được định vị là một chiếc <a href="https://www.coolmate.me/collection/ao-polo-nam-choi-the-thao" target="_blank" rel="noopener">áo polo thể thao nam</a> hiệu suất cao, sản phẩm này vượt xa những chiếc <a href="https://www.coolmate.me/collection/ao-polo-nam" target="_blank" rel="noopener">áo polo nam</a> thông thường. Chất liệu 100% <a href="https://www.coolmate.me/post/vai-polyester-la-gi" target="_blank" rel="noopener">vải polyester</a> là gì được xử lý với công nghệ Quick-Dry (Nhanh khô) và <a href="https://www.coolmate.me/post/vai-wicking-la-gi-4375" target="_blank" rel="noopener">vải wicking</a> (Thấm hút tốt), giúp mồ hôi nhanh chóng được chuyển ra bề mặt vải và bay hơi, giữ cho bạn luôn khô ráo, thoáng mát. Với định lượng vải chỉ 155gsm, áo siêu nhẹ và bề mặt vải có nhiều lỗ nhỏ li ti, gia tăng khả năng thoát ẩm, mang lại cảm giác dễ chịu tối đa khi vận động, xứng đáng là một item hàng đầu trong dòng <a href="https://www.coolmate.me/collection/ao-nam-choi-the-thao" target="_blank" rel="noopener">áo thể thao nam</a>.</p><p><img src="https://mcdn.coolmate.me/image/July2025/ao-polo-the-thao-promaxS1.jpg" alt="&Aacute;o polo thể thao Promax S1" width="1000" style="width: 1000; height: 731;" height="731"></p><p style="text-align: justify;"><img src="https://mcdn.coolmate.me/image/July2025/vai-the-thao-poly.jpg" alt="C&ocirc;ng nghệ vải" width="1000" style="width: 1000; height: 626;" height="626"></p><h3 style="text-align: justify;">Thiết Kế Năng Động &amp; Chi Tiết Thông Minh</h3><p style="text-align: justify;">Áo Polo Nam Thể Thao Promax-S1 sở hữu <a href="https://www.coolmate.me/post/regular-fit-la-gi-395" target="_blank" rel="noopener">kiểu dáng Regular Fit</a>, mang đến sự vừa vặn lý tưởng, không quá ôm sát cũng không quá rộng, đảm bảo sự thoải mái tối ưu cho mọi cử động. Thiết kế này là điểm nhấn trong <a href="https://www.coolmate.me/collection/do-the-thao" target="_blank" rel="noopener" class="in-cell-link">quần áo thể thao</a>, phù hợp với nhiều vóc dáng nam giới trong các hoạt động thể thao đa dạng.</p><p><img src="https://mcdn.coolmate.me/image/July2025/be-mat-vai.jpg" alt="bề mặt vải" width="1000" style="width: 1000; height: 949;" height="949"></p><p style="text-align: justify;">Cổ bẻ polo phối 2 nút cài: Giữ vẻ lịch sự đặc trưng, cho phép điều chỉnh độ thông thoáng.</p><ul><li><p>Tay áo ngắn, thiết kế năng động: Đảm bảo sự linh hoạt tối đa cho vai và cánh tay.</p></li><li><p>Bề mặt vải cấu trúc lỗ nhỏ: Tăng cường thoát khí, hỗ trợ làm mát và nhanh khô.</p></li><li><p>Logo Coolmate tinh tế: In sắc nét, khẳng định chất lượng thương hiệu.</p></li></ul><p style="text-align: justify;"><strong>&gt;&gt;&gt;Xem thêm:</strong><a href="https://www.coolmate.me/post/size-ao-polo-nam"> Bảng chọn size áo polo nam chuẩn đẹp được áp dụng nhiều nhất hiện nay</a></p><h3 style="text-align: justify;">Linh Hoạt Trong Mọi Hoàn Cảnh</h3><p style="text-align: justify;">Chiếc áo polo Promax-S1 là minh chứng cho sự đa năng, sẵn sàng đồng hành cùng bạn từ sân tập đến những buổi gặp gỡ thường ngày.</p><ul><li><p><strong>Chơi thể thao:</strong> Hoàn hảo cho các môn vận động như tennis, chạy bộ, golf.</p></li><li><p><strong>Đi làm, đi chơi: </strong>Lịch sự, năng động khi kết hợp cùng quần kaki hoặc jeans.</p></li><li><p><strong>Mặc ở nhà</strong>: Mang lại sự thoải mái tuyệt đối cho các hoạt động tại gia.</p></li></ul><p style="text-align: justify;">Để có một set đồ hoàn chỉnh, bạn có thể phối áo cùng một chiếc <a href="https://www.coolmate.me/collection/quan-short-nam" target="_blank" rel="noopener">quần short nam</a> để tạo nên bộ <a href="https://www.coolmate.me/collection/coolmate-activewear" target="_blank" rel="noopener">đồ thể thao nam</a> năng động và khỏe khoắn.</p><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm: </strong><a href="https://www.coolmate.me/post/phoi-do-voi-ao-polo-nam" target="_blank" rel="noopener">20+ Cách Phối Đồ Với Áo Polo Nam Đơn Giản, Chuẩn Men, Hot Trend 2025</a></p><p><img src="https://mcdn.coolmate.me/image/July2025/phu-hop-cho-nhieu-hoat-dong.jpg" alt="Ph&ugrave; hợp cho mọi hoạt động" width="1000" style="width: 1000; height: 1500;" height="1500"></p><h3><img src="https://mcdn.coolmate.me/image/July2025/phu-hop-cho-nhieu-hoat-dong2.jpg" alt="Ph&ugrave; hợp cho mọi hoạt động" width="1000" style="width: 1000; height: 1367;" height="1367"></h3><h3 style="text-align: justify;">Bí Quyết Giữ Sản Phẩm Bền Đẹp</h3><p>Để chiếc áo polo thể thao của bạn luôn giữ được chất lượng và phom dáng tốt nhất, hãy lưu ý những điều sau:</p><ul><li><p>Giặt máy ở chế độ nhẹ và nhiệt độ thấp để bảo vệ cấu trúc vải.</p></li><li><p>Không sử dụng chất tẩy rửa mạnh hoặc giặt khô.</p></li><li><p>Sấy ở nhiệt độ thấp hoặc phơi khô tự nhiên ở nơi thoáng mát.</p></li></ul><p>Việc tuân thủ đúng hướng dẫn sẽ giúp sản phẩm của bạn bền đẹp dài lâu. Tìm hiểu thêm về <a href="https://www.coolmate.me/post/cach-giat-ao-polo-nam" target="_blank" rel="noopener">cách giặt áo polo nam</a> đúng cách giúp áo bền đẹp theo thời gian để chăm sóc tốt nhất cho chiếc áo của mình.</p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 239000.00, 215000.00, true, null, '2026-07-01 13:44:05', '2026-07-01 13:44:05');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (8, 6, 'Áo Polo nam Premium Cotton Linen', 'ao-polo-nam-premium-cotton-linen', 'Cotton & Linen đều là các loại sợi tự nhiên, có độ thấm hút mồ hôi hiệu quả và tản nhiệt tốt', '<h2 style="text-align: center;">Áo Polo Nam Premium Cotton Linen - Thoáng Mát Tự Nhiên, Phong Thái Lịch Lãm</h2><p style="text-align: justify;"><strong>Áo Polo Premium Cotton Linen</strong> là sự lựa chọn hoàn hảo cho những ngày nóng bức, không chỉ mang lại cảm giác thoáng mát mà còn phong thái thanh lịch tự nhiên Với sự kết hợp 70% <a href="https://www.coolmate.me/post/vai-cotton-la-gi" target="_blank" rel="noopener">Cotton</a> mang lại sự mềm mại, đứng form và 30% <a href="https://www.coolmate.me/post/vai-linen-la-gi-va-kien-thuc-ve-vai-linen" target="_blank" rel="noopener">Linen</a> phát huy tối đa khả năng thoáng khí và tản nhiệt vượt trội. Sự pha trộn này tạo nên một bề mặt vải có độ xước nhẹ đặc trưng, không chỉ giúp thấm hút mồ hôi tốt mà còn mang lại vẻ ngoài tinh tế. Cảm nhận thực tế khi mặc là sự mát mẻ, nhẹ nhàng và thoải mái, vừa giữ được sự chỉn chu cần thiết, vừa mang đậm nét tự nhiên, phóng khoáng.</p><h2 style="text-align: justify;">Thiết Kế Cổ Button-Down &amp; Chi Tiết Tinh Tế</h2><p style="text-align: justify;">Áo có dáng <a href="https://www.coolmate.me/post/regular-fit-la-gi-395" target="_blank" rel="noopener">Regular Fit</a> – một form <a href="https://www.coolmate.me/collection/ao-nam" target="_blank" rel="noopener">áo nam</a> kinh điển, cân đối giữa vai, ngực và eo, mang lại sự thoải mái tối đa mà không quá rộng, phù hợp với hầu hết mọi vóc dáng nam giới Việt.</p><ul><li><p><strong>Cổ áo Button-Down:</strong> Thiết kế cổ có nút gài cố định giúp lá cổ luôn đứng dáng và ổn định, tạo nên vẻ ngoài chỉn chu ngay cả khi không cài cúc trên cùng.</p></li><li><p><strong>Cúc áo đồng màu:</strong> Thể hiện sự tinh tế, mang lại vẻ ngoài hài hòa, liền mạch cho tổng thể.</p></li><li><p><strong>Mác dệt kẹp sườn:</strong> Logo được đặt một cách khéo léo ở đường may bên sườn, là một điểm nhấn nhận diện thương hiệu tinh tế.</p></li></ul><blockquote><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/size-ao-polo-nam" target="_blank" rel="noopener">Bảng Size Áo Polo Nam Đầy Đủ Và Cách Chọn Size Chuẩn Nhất 2025</a></p></blockquote><h2 style="text-align: justify;">Thanh Lịch Cho Mọi Dịp</h2><p style="text-align: justify;">Sự kết hợp giữa chất liệu độc đáo và thiết kế chỉn chu giúp chiếc <strong>Áo Polo Premium Cotton Linen</strong> trở thành một item linh hoạt cho nhiều hoàn cảnh.</p><ul><li><p><strong>Môi trường công sở:</strong> Hoàn hảo cho những ngày đi làm không yêu cầu quá trang trọng (semi-formal), dễ dàng phối cùng <a href="https://www.coolmate.me/collection/quan-kaki-nam" target="_blank" rel="noopener">quần kaki nam</a>.</p></li><li><p><strong>Du lịch &amp; Dạo phố:</strong> Mang lại phong cách tối giản, thanh lịch khi kết hợp cùng quần short linen hoặc <a href="https://www.coolmate.me/collection/quan-jeans-nam" target="_blank" rel="noopener">quần jeans</a> sáng màu.</p></li></ul><blockquote><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/phoi-do-voi-ao-polo-nam" target="_blank" rel="noopener">20+ Cách Phối Đồ Với Áo Polo Nam Đơn Giản, Chuẩn Men, Hot Trend 2025</a></p></blockquote><h2 style="text-align: justify;">Bí Quyết Giữ Sản Phẩm Bền Đẹp</h2><ul><li><p>Để giữ màu sắc và cấu trúc vải những chiếc <a href="https://www.coolmate.me/collection/ao-polo-nam" target="_blank" rel="noopener">áo polo</a> của bạn, hãy luôn lộn trái áo trước khi giặt và ưu tiên giặt bằng nước lạnh.</p></li><li><p>Sau khi giặt, hãy giũ phẳng áo trước khi phơi để hạn chế nếp nhăn tự nhiên đặc trưng của vải Linen.</p></li><li><p>Hạn chế sấy ở nhiệt độ cao vì sẽ làm co rút vải.</p></li></ul><blockquote><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/cach-giat-ao-polo-nam" target="_blank" rel="noopener">Cách giặt áo polo nam đúng, chuẩn, bền màu theo thời gian</a></p></blockquote>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 399000.00, null, true, null, '2026-07-01 13:49:06', '2026-07-01 13:49:06');
