INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (10, 22, 'Áo Tee Ribbed', 'ao-tee-ribbed', 'Giúp cử động linh hoạt, bề mặt chải nhẹ tăng độ mềm mịn và thẩm mỹ', '<h2 style="text-align: center;">Áo Tee Ribbed - Tôn Dáng Tự Nhiên, Thoải Mái Vận Động</h2><p style="text-align: justify;"><strong>Áo Tee Ribbed </strong>là chiếc <a href="https://www.coolmate.me/collection/ao-cropped-top" target="_blank" rel="noopener">áo croptop nữ</a> với sự kết hợp hoàn hảo giữa phong cách và hiệu suất, được thiết kế để trở thành người bạn đồng hành lý tưởng từ phòng tập đến những buổi dạo phố. Điểm đặc biệt của chiếc <a href="https://www.coolmate.me/collection/ao-thun-nu" target="_blank" rel="noopener">áo thun nữ</a> nằm ở chất liệu vải gân nổi độc đáo, không chỉ mang lại vẻ ngoài thời trang mà còn giúp che khuyết điểm một cách tinh tế. Trái tim của mẫu <a href="https://www.coolmate.me/collection/ao-nu" target="_blank" rel="noopener">áo nữ</a> này là sự pha trộn giữa 79% Nylon và 21% <a href="https://www.coolmate.me/post/spandex-la-gi" target="_blank" rel="noopener">vải spandex</a>, tạo nên một chất liệu co giãn 4 chiều vượt trội, siêu nhẹ và mềm mại trên da. <a href="https://www.coolmate.me/collection/ao-nu-choi-the-thao" target="_blank" rel="noopener">Áo thể thao nữ</a> với bề mặt vải được chải nhẹ, tăng cường cảm giác mịn màng và êm ái, cho phép bạn tự do thực hiện mọi động tác từ yoga, pilates đến các bài tập cường độ cao mà không gặp bất kỳ sự cản trở nào.</p><h2 style="text-align: justify;">Thiết Kế Slim Fit Ôm Gọn Cùng Điểm Nhấn Nhún Eo</h2><p style="text-align: justify;">Sản phẩm sở hữu <a href="https://www.coolmate.me/post/slim-fit-la-gi-cach-dien-ao-thun-slim-fit-ton-body-471" target="_blank" rel="noopener">kiểu dáng slim fit</a> hiện đại, được tính toán để ôm nhẹ theo đường cong cơ thể, tôn lên vóc dáng một cách tự nhiên nhưng vẫn đảm bảo sự thoải mái tối đa.</p><ul><li><p><strong>Kiểu dáng:</strong> Slim Fit ôm gọn, tôn dáng.</p></li><li><p><strong>Chi tiết:</strong> Điểm nhấn nhún eo hai bên hông tạo hiệu ứng thị giác giúp vòng hai trông thon gọn hơn, đồng thời là một chi tiết thiết kế nữ tính, tinh tế.</p></li></ul><p style="text-align: justify;"><em>Thông tin người mẫu: Mẫu cao 1m69, nặng 52kg, số đo 76-60-90(cm) và đang mặc size S.</em></p><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/bi-quyet-chon-size-ao-thun-nu-chuan-nhu-may-do-5680" target="_blank" rel="noopener">Bí quyết chọn size áo thun nữ chuẩn như may đo</a></p><h2 style="text-align: justify;">Đa Năng Trong Mọi Hoàn Cảnh</h2><p style="text-align: justify;">Chiếc <a href="https://www.coolmate.me/collection/ao-thun-nu-choi-the-thao" target="_blank" rel="noopener">áo thun thể thao nữ</a> này là lựa chọn linh hoạt, đáp ứng mọi nhu cầu hoạt động của bạn trong ngày:</p><ul><li><p><strong>Luyện tập thể thao:</strong> Hoàn hảo cho set <a href="https://www.coolmate.me/collection/coolmate-activewear-nu" target="_blank" rel="noopener">đồ thể thao nữ</a> vớicác buổi tập yoga, pilates, gym hay các hoạt động thể chất khác.</p></li><li><p><strong>Trang phục hàng ngày:</strong> Dễ dàng phối cùng quần jeans, <a href="https://www.coolmate.me/collection/quan-short-nu" target="_blank" rel="noopener">quần short nữ</a> hoặc chân váy để tạo nên một outfit năng động, trẻ trung khi đi cà phê, dạo phố.</p></li></ul><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/phoi-do-voi-ao-thun-nu-11-cach-mix-do-chuan-gu-trendy-5694" target="_blank" rel="noopener">11+ Cách phối đồ với áo thun nữ giúp nàng cân mọi style</a></p><h2 style="text-align: justify;">Bí Quyết Giữ Sản Phẩm Bền Đẹp</h2><p style="text-align: justify;">Để áo Tee Ribbed luôn giữ được độ đàn hồi và phom dáng, hãy chú ý đến cách bảo quản sau:</p><ul><li><p>Giặt máy ở chế độ nhẹ nhàng với nước lạnh để bảo vệ cấu trúc sợi vải.</p></li><li><p>Sấy khô ở nhiệt độ thấp hoặc phơi trong bóng râm, tránh ánh nắng mặt trời trực tiếp.</p></li><li><p>Không sử dụng chất tẩy rửa mạnh và tuyệt đối không giặt khô.</p></li></ul><p style="text-align: justify;">Việc tuân thủ những hướng dẫn trên sẽ giúp sản phẩm của bạn luôn bền đẹp như mới. Để giữ áo luôn sạch sẽ, bạn có thể tìm hiểu thêm về <a href="https://www.coolmate.me/post/cam-nang-chi-tiet-16-cach-xu-ly-vet-ban-ao-thun-hieu-qua-nhat-5703" target="_blank" rel="noopener">cách xử lý vết bẩn áo thun</a> một cách hiệu quả.</p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 299000.00, null, true, null, '2026-07-01 14:02:13', '2026-07-01 14:02:13');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (11, 22, 'Áo Croptop nữ Cotton Poly', 'ao-croptop-nu-cotton-poly', 'Độ dài ngắn, độ rộng vừa. Tạo sự cá tính và Mang lại cảm giác thoải mái, thanh lịch, phù hợp phối với chân váy, quần shorts, jean', '<p></p>', '{"Phù hợp": "Thoáng khí, Nhanh khô, Hạn chế nhăn", "Tính năng": "Giặt máy nhẹ - Sấy ở mức nhiệt thấp  Không dùng chất tẩy - Không giặt khô", "Bảo quản": "Giặt máy nhẹ - Sấy ở mức nhiệt thấp  Không dùng chất tẩy - Không giặt khô", "Công nghệ": " 60% Cotton 40% Polyester", "Kiểu dáng": "Đi làm, Đi chơi", "Chất liệu": "Relax  Mẫu cao 1m70, nặng 55kg, 84/68/94(cm) - Size S"}', 169000.00, null, true, null, '2026-07-01 14:09:19', '2026-07-01 14:09:19');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (12, 22, 'Áo Croptop nữ 100% Cotton', 'ao-croptop-nu-100-cotton', 'Mang lại cảm giác dễ chịu khi mặc, phù hợp cho cả ngày dài hoạt động, bề mặt vải siêu mịn, nhẹ và thoáng khí vượt trội', '<p></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 179000.00, null, true, null, '2026-07-01 14:12:26', '2026-07-01 14:12:26');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (13, 22, 'Áo tank bơi nữ Coolmate Cutline', 'ao-tank-boi-nu-coolmate-cutline', 'Chất liệu có khả năng chống Clo cao phù hợp bơi thường xuyên, thoáng khí khi vận động hạn chế mài mòn và giữ form tốt', '<p>Khám phá sự kết hợp hoàn hảo giữa phong cách và hiệu suất với Áo tank bơi nữ Coolmate Cutline, một lựa chọn tuyệt vời trong danh mục <a href="https://www.coolmate.me/collection/ao-nu" target="_blank" rel="noopener">Áo nữ</a> và thuộc dòng <a href="https://www.coolmate.me/collection/ao-singlet-nu" target="_blank" rel="noopener">Áo singlet nữ</a>. Được thiết kế đặc biệt cho phái nữ yêu thích bộ môn bơi lội và các hoạt động thể thao dưới nước, mẫu áo này mang đến sự thoải mái tối đa nhờ chất liệu cao cấp 80% Nylon và 20% Spandex. Với kiểu dáng ôm sát và công nghệ tiên tiến, chiếc áo tank bơi này hứa hẹn sẽ là người bạn đồng hành lý tưởng cho mọi buổi tập luyện, giúp bạn tự tin thể hiện bản thân.</p><h3>Điều gì khiến Áo tank bơi nữ Coolmate Cutline được yêu thích?</h3><h4>1. Co giãn 4 chiều</h4><p>Trải nghiệm sự tự do vận động không giới hạn với <a href="https://www.coolmate.me/collection/ao-singlet-nu-boi-loi" target="_blank" rel="noopener">Áo tank bơi nữ</a> Coolmate Cutline. Được dệt từ sợi vải có khả năng co giãn 4 chiều vượt trội, chiếc áo này linh hoạt theo từng chuyển động của cơ thể bạn. Chất liệu đàn hồi tốt giúp hỗ trợ tối ưu cho mọi hoạt động, từ những sải bơi mạnh mẽ dưới nước đến các bài tập yoga hay giãn cơ. Cảm giác thoải mái này sẽ theo bạn suốt buổi tập, cho phép bạn tập trung hoàn toàn vào hiệu suất của mình mà không bị vướng víu hay khó chịu.</p><h4>2. Kháng Clo</h4><p>Bảo vệ trang phục của bạn khỏi tác động của hóa chất hồ bơi với công nghệ kháng clo tiên tiến. Chất liệu vải được xử lý đặc biệt để chống lại sự ăn mòn của clo, giúp quần áo bơi của bạn bền màu lâu hơn, hạn chế tình trạng mục vải, giãn vải hay xuống cấp. Điều này không chỉ giúp bạn tiết kiệm chi phí thay mới mà còn giữ cho chiếc áo luôn như mới, form dáng chuẩn đẹp sau mỗi lần sử dụng. Bạn có thể hoàn toàn yên tâm bơi lội thường xuyên mà không cần lo lắng về việc trang phục sẽ nhanh chóng bị hư hỏng.</p><h4>3. Chống tia UV</h4><p>Dù bạn bơi trong nhà hay ngoài trời, Áo tank bơi nữ Coolmate Cutline đều mang đến sự bảo vệ cần thiết. Với khả năng chống tia UV hiệu quả, chiếc áo giúp giảm thiểu tác động tiêu cực của ánh nắng mặt trời lên làn da của bạn. Điều này hỗ trợ ngăn ngừa cháy nắng và sạm màu da, cho phép bạn thoải mái tận hưởng các hoạt động dưới nắng mà không cần lo ngại. Cảm giác an tâm này giúp bạn tự tin hơn khi tham gia các môn thể thao dưới nước hoặc các hoạt động ngoài trời khác.</p><h4>4. Trượt nước</h4><p>Trải nghiệm sự nhẹ nhàng và thoải mái tối đa khi xuống nước với công nghệ trượt nước ưu việt. Bề mặt vải được xử lý để hạn chế tối đa việc bám nước, giúp chiếc áo giữ được độ nhẹ nhàng ngay cả khi đã xuống nước. Sau khi sử dụng, áo cũng sẽ khô nhanh hơn đáng kể, mang lại cảm giác dễ chịu và không hề nặng nề hay ướt sũng. Điều này đặc biệt quan trọng khi bạn cần di chuyển hoặc tham gia các hoạt động khác ngay sau khi bơi.</p><h3>Thông số chi tiết sản phẩm</h3><ul><li><p>Chất liệu: 80% Nylon + 20% Spandex</p></li><li><p>Fit: tight-fit</p></li><li><p>Màu sắc: đen, xanh navy</p></li><li><p>Công nghệ: Kháng clo, Chống tia UV, Trượt nước</p></li><li><p>Thiết kế: lưng racerback, ôm dáng</p></li></ul><h3>Áo tank bơi nữ Coolmate Cutline phù hợp với ai?</h3><p>Chiếc Áo tank bơi nữ Coolmate Cutline là sự lựa chọn lý tưởng dành cho những người phụ nữ yêu thích vận động dưới nước.</p><p>Nếu bạn là người đam mê bơi lội, thường xuyên tham gia các lớp học hoặc đơn giản là muốn có một bộ trang phục bơi ôm dáng, linh hoạt và thoải mái, thì đây chính là sản phẩm dành cho bạn. Áo tank bơi này đặc biệt phù hợp cho mục đích bơi lội, tập luyện thường xuyên dưới nước, hoặc khi bạn cần một mẫu áo gọn gàng, không gây cản trở khi vận động.</p><p>Dù là bơi tại hồ bơi, biển hay tham gia các môn thể thao dưới nước khác, bạn đều có thể tự tin sử dụng quanh năm.</p><h3>Mix &amp; Match cùng Áo tank bơi nữ Coolmate Cutline</h3><ul><li><p><strong>Phối cùng quần bơi nữ:</strong> Tạo nên một bộ trang phục bơi hoàn chỉnh và năng động. Sự kết hợp này mang đến vẻ ngoài gọn gàng, chuyên nghiệp cho các buổi tập luyện hoặc thư giãn tại hồ bơi, biển.</p></li><li><p><strong>Kết hợp cùng kính bơi:</strong> Đừng quên trang bị kính bơi chất lượng để bảo vệ mắt và nâng cao hiệu quả bơi lội. Kính bơi không chỉ là phụ kiện thiết yếu mà còn tạo điểm nhấn cho tổng thể trang phục.</p></li><li><p><strong>Kết hợp cùng áo choàng/khăn tắm sau bơi:</strong> Sau khi rời khỏi mặt nước, một chiếc áo choàng hoặc khăn tắm mềm mại sẽ giúp bạn giữ ấm và thoải mái. Đây là bước hoàn thiện mang đến trải nghiệm thư giãn trọn vẹn sau khi bơi. Bạn có thể tham khảo thêm các mẫu Áo singlet nữ bơi lội để có thêm lựa chọn phối đồ.</p></li></ul><h3>Câu hỏi thường gặp về Áo tank bơi nữ Coolmate Cutline</h3><h4>1. Áo tank bơi nữ Coolmate Cutline được làm từ chất liệu gì?</h4><p>Chiếc áo được chế tác từ sự kết hợp hoàn hảo giữa 80% Nylon và 20% Spandex. Nylon mang lại độ bền vượt trội và khả năng chống nhăn, giúp áo giữ form dáng sau nhiều lần sử dụng. Spandex bổ sung khả năng co giãn tuyệt vời, đảm bảo sự thoải mái và ôm sát cơ thể, hỗ trợ tối đa cho mọi hoạt động.</p><h4>2. Áo có form dáng như thế nào?</h4><p>Sản phẩm có thiết kế &quot;&quot;tight-fit&quot;&quot;, ôm sát cơ thể theo form dáng tự nhiên. Điểm nhấn đặc biệt là phần lưng racerback, không chỉ tạo nên vẻ ngoài năng động, hiện đại mà còn giúp giải phóng vai, tăng cường sự linh hoạt và thoáng khí khi vận động, giảm cảm giác bí bách.</p><h4>3. Sản phẩm có phù hợp để bơi thường xuyên không?</h4><p>Hoàn toàn phù hợp. Nhờ các tính năng kháng clo, trượt nước và độ co giãn 4 chiều, chiếc áo tank bơi này được thiết kế để chịu được tần suất sử dụng cao trong môi trường hồ bơi. Chất liệu bền bỉ và nhanh khô giúp duy trì form dáng và màu sắc, đảm bảo bạn luôn có trải nghiệm bơi lội tốt nhất.</p><h4>4. Áo tank bơi nữ Coolmate Cutline có thể dùng cho hoạt động ngoài trời không?</h4><p>Có. Khả năng chống tia UV của áo là một lợi thế lớn khi hoạt động ngoài trời, giúp bảo vệ da khỏi tác hại của ánh nắng. Mặc dù được thiết kế chủ yếu cho bơi lội, áo vẫn rất hữu ích cho các hoạt động thể thao hoặc thư giãn ngoài trời, tùy thuộc vào điều kiện thời tiết và môi trường cụ thể.</p><h4>5. Cần lưu ý gì khi giặt và bảo quản áo bơi này?</h4><p>Để giữ áo luôn bền đẹp, bạn nên giặt bằng tay với nước lạnh, tránh dùng chất tẩy rửa mạnh. Phơi áo ở nơi thoáng mát, tránh ánh nắng trực tiếp. Bảo quản ở nơi khô ráo, tránh ẩm mốc. Việc tuân thủ các hướng dẫn này sẽ giúp duy trì độ co giãn và màu sắc của chất liệu Nylon/Spandex.</p><h3>Hướng dẫn bảo quản Áo tank bơi nữ Coolmate Cutline</h3><ul><li><p><strong>Giặt:</strong> Nên giặt tay bằng nước lạnh và xà phòng nhẹ. Tránh sử dụng thuốc tẩy hoặc chất làm mềm vải.</p></li><li><p><strong>Phơi:</strong> Phơi áo ở nơi thoáng mát, tránh ánh nắng trực tiếp để giữ màu sắc và độ bền của vải. Không sử dụng máy sấy.</p></li><li><p><strong>Bảo quản:</strong> Cất giữ áo ở nơi khô ráo, thoáng khí. Tránh để gần các vật sắc nhọn hoặc hóa chất.</p></li><li><p><strong>Lưu ý theo chất liệu:</strong> Với chất liệu Nylon và Spandex, tránh giặt bằng nước nóng hoặc sấy ở nhiệt độ cao để không làm ảnh hưởng đến độ co giãn và form dáng của áo.</p></li></ul>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 149000.00, 179000.00, true, null, '2026-07-01 14:15:38', '2026-07-01 14:15:38');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (14, 22, 'Áo crop cổ V Exdry ProActive World Cup', 'ao-crop-co-v-exdry-proactive-world-cup', 'Kỹ thuật dệt jacquard giúp ổn định cấu trúc vải, giữ form tốt và hạn chế biến dạng sau nhiều lần mặc và giặt', '<p></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 249000.00, 199000.00, true, null, '2026-07-01 14:22:34', '2026-07-01 14:22:34');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (15, 22, 'Áo crop Jacquard Motion Exdry ProActive World Cup', 'ao-crop-jacquard-motion-exdry-proactive-world-cup', 'Vải tái chế với cấu trúc jacquard và các rãnh/sọc dệt nổi giúp tăng cường lưu thông không khí, hỗ trợ tản nhiệt tốt', '<p></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 379000.00, 279000.00, true, null, '2026-07-01 14:31:16', '2026-07-01 14:31:16');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (16, 22, 'Tanktop Pickleball nữ FlexRacer Back', 'tanktop-pickleball-nu-flexracer-back', 'Kết cấu Interlock Knit tạo bề mặt vải mềm mịn, chắc tay nhưng vẫn linh hoạt khi di chuyển, kết hợp sợi polyester tái chế giúp tăng độ bền', '<h2 style="text-align: center;">Tanktop Pickleball Nữ Flexracer Back - Tôn Dáng Và Linh Hoạt Trên Sân Đấu</h2><p style="text-align: justify;">Chiếc Tanktop Pickleball nữ FlexRacer Back được sinh ra để đồng hành cùng phái nữ trong từng chuyển động, dù là trên sân tập hay trong các hoạt động hàng ngày. Nền tảng của sự thoải mái này đến từ sự kết hợp giữa 66% sợi <a href="https://www.coolmate.me/blog/recycled-polyester-4391" target="_blank" rel="noopener">Recycled Polyeste</a> và hàm lượng <a href="https://www.coolmate.me/blog/spandex-la-gi" target="_blank" rel="noopener">Spandex</a> lên đến 34%. Sợi Polyester tái chế không chỉ góp phần vào thời trang bền vững mà còn mang lại đặc tính siêu nhẹ và thấm hút mồ hôi hiệu quả. Trong khi đó, hàm lượng Spandex vượt trội mang đến khả năng co giãn đa chiều đáng kinh ngạc cho chiếc <a href="https://www.coolmate.me/collection/ao-singlet-nu" target="_blank" rel="noopener">áo singlet nữ</a>, cho phép bạn tự do thực hiện những cú vung vợt hay xoay người mà không gặp bất kỳ cản trở nào. Kỹ thuật dệt Interlock Knit tạo ra bề mặt vải <a href="https://www.coolmate.me/collection/pickleball-tennis-cho-nu" target="_blank" rel="noopener">quần áo pickleball nữ</a> mềm mịn, chắc chắn, mang lại cảm giác dễ chịu khi tiếp xúc với da và giữ form áo bền bỉ sau nhiều lần giặt.</p><h3 style="text-align: justify;">Thiết kế Slim fit ôm trọn đường cong cơ thể</h3><p style="text-align: justify;"><a href="https://www.coolmate.me/collection/ao-nu" target="_blank" rel="noopener">Áo nữ</a> sở hữu form dáng <a href="https://www.coolmate.me/blog/slim-fit-la-gi-cach-dien-ao-thun-slim-fit-ton-body-471" target="_blank" rel="noopener">Slim fit</a> được tính toán dựa trên đường cong cơ thể của phái nữ, giúp tôn lên vòng eo và phần vai một cách tự nhiên mà không gây cảm giác bó sát khó chịu.</p><ul><li><p>Thiết kế lưng chữ Y với một khoảng hở tinh tế không chỉ tạo điểm nhấn thời trang mà còn giải phóng hoàn toàn phần xương bả vai, tối ưu cho các động tác cần sự linh hoạt.</p></li><li><p>Áo được tích hợp sẵn lớp mút bra, mang lại sự tiện lợi và khả năng nâng đỡ vừa phải, giúp bạn tự tin vận động.</p></li><li><p>Logo Pickleball được dệt bản bự, tạo điểm nhấn khỏe khoắn và đầy màu sắc.</p></li></ul><p style="text-align: justify;">Xem thêm: <a href="https://www.coolmate.me/blog/bi-quyet-chon-size-ao-singlet-nu-chuan-dep-tu-tin-van-dong-5665" target="_blank" rel="noopener">Chọn size áo singlet nữ: Bí quyết &amp; Bảng size chuẩn nhất</a></p><h3 style="text-align: justify;">Đa năng cho mọi hoạt động yêu thích</h3><p style="text-align: justify;">Đừng chỉ giới hạn chiếc áo này trong sân đấu, nó hoàn toàn có thể trở thành một item <a href="https://www.coolmate.me/collection/do-nu" target="_blank" rel="noopener">đồ nữ</a> không thể thiếu trong tủ đồ năng động của bạn:</p><ul><li><p>Chơi các môn thể thao đòi hỏi sự linh hoạt: Pickleball, tennis, cầu lông.</p></li><li><p>Tập luyện tại phòng gym, tham gia các lớp yoga, pilates hoặc vũ đạo.</p></li><li><p>Phối cùng quần jeans, <a href="https://www.coolmate.me/collection/quan-short-nu" target="_blank" rel="noopener">quần short nữ</a> hoặc <a href="https://www.coolmate.me/collection/vay-dam-nu" target="_blank" rel="noopener">váy thể thao nữ</a> để dạo phố, cà phê.</p></li></ul><p style="text-align: justify;">Hãy khám phá thêm bộ sưu tập <a href="https://www.coolmate.me/collection/coolmate-activewear-nu" target="_blank" rel="noopener">đồ thể thao nữ</a> của chúng tôi để tìm thấy những mảnh ghép hoàn hảo cho phong cách <a href="https://www.coolmate.me/collection/pickleball-tennis" target="_blank" rel="noopener">quần áo pickleball</a> của bạn.</p><p style="text-align: justify;">Xem thêm: <a href="https://www.coolmate.me/blog/cam-nang-ve-xu-huong-ao-singlet-nu-cach-mac-dep-cho-nang-trong-mua-he-nay-5656" target="_blank" rel="noopener">Xu hướng áo singlet nữ mới nhất &amp; cách mặc đẹp cho nàng</a></p><h3 style="text-align: justify;">Bí quyết giữ sản phẩm bền đẹp</h3><p style="text-align: justify;">Để chiếc <a href="https://www.coolmate.me/collection/ao-nu-choi-the-thao" target="_blank" rel="noopener">áo thể thao nữ</a> luôn giữ được độ thoáng khí, form dáng chuẩn và màu sắc bền đẹp theo thời gian, bạn nên lưu ý một vài nguyên tắc chăm sóc và giặt giũ dưới đây.</p><ul><li><p>Hãy giặt chiếc tanktop này ngay sau khi tập luyện để mồ hôi và vi khuẩn không làm ảnh hưởng đến cấu trúc vải.</p></li><li><p>Tuyệt đối không sử dụng nước xả vải, vì chúng sẽ tạo một lớp màng làm giảm khả năng thấm hút và thoát ẩm của áo.</p></li><li><p>Ưu tiên giặt máy ở chế độ nhẹ với nước lạnh để bảo vệ độ co giãn cao của sợi Spandex và lớp bra tích hợp.</p></li></ul><p style="text-align: justify;">Xem thêm: <a href="https://www.coolmate.me/blog/cach-giat-do-the-thao-khong-bi-phai-mau-3655" target="_blank" rel="noopener">9 cách giặt đồ thể thao không bị phai màu, không bị giãn</a></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 329000.00, null, true, null, '2026-07-01 14:35:05', '2026-07-01 14:35:05');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (17, 22, 'Áo croptop Pickleball Drive Mesh Essentials', 'ao-croptop-pickleball-drive-mesh-essentials', 'Thấm hút mồ hôi khi vận động nhờ công nghệ ExDry giúp mồ hôi, hơi ẩm nhanhchóng bay hơi, giữ cơ thể khô thoáng', '<h2 style="text-align: center;">Áo Croptop Pickleball Drive Mesh Essentials - Làm Chủ Sân Đấu, Khẳng Định Phong Cách</h2><p style="text-align: justify;">Là sự kết hợp hoàn hảo giữa hiệu suất và phong cách, <strong>Áo Croptop Pickleball Drive Mesh Essentials</strong> được tạo ra để bạn luôn tỏa sáng trên sân đấu. Đây không chỉ là một item thời thượng trong tủ <a href="https://www.coolmate.me/collection/do-nu" target="_blank" rel="noopener">đồ nữ</a>, mà là một chiếc <a href="https://www.coolmate.me/collection/ao-nu-pickleball" target="_blank" rel="noopener">áo pickleball nữ</a> chuyên dụng, thuộc bộ sưu tập <a href="https://www.coolmate.me/collection/coolmate-activewear-nu" target="_blank" rel="noopener">đồ thể thao nữ</a> hiện đại. Mẫu <a href="https://www.coolmate.me/collection/ao-cropped-top" target="_blank" rel="noopener">áo crop top</a> này sử dụng chất liệu <a href="https://www.coolmate.me/blog/recycled-polyester-4391" target="_blank" rel="noopener">Recycled Polyester</a> co giãn 4 chiều, tích hợp công nghệ <a href="https://www.coolmate.me/blog/cong-nghe-exdry-4439" target="_blank" rel="noopener">Ex-Dry</a>, mang đến cảm giác khô thoáng và tự do trong từng cú đánh.</p><h2 style="text-align: justify;">Thiết Kế Tôn Dáng, Tối Ưu Cho Từng Cú Drive</h2><p style="text-align: justify;">Áo sở hữu form Slim với dáng croptop thời thượng, được thiết kế để ôm nhẹ, khéo léo tôn lên đường cong cơ thể mà vẫn đảm bảo sự thoải mái tối đa khi vận động.</p><ul><li><p><strong>Hệ thống phối lưới thông minh:</strong> Các mảng vải lưới được bố trí chiến lược ở hai bên sườn, hoạt động như một hệ thống làm mát, giúp món <a href="https://www.coolmate.me/collection/do-the-thao" target="_blank" rel="noopener">đồ thể thao</a> này mang lại cảm giác luôn khô ráo và mát mẻ.</p></li><li><p><strong>Co giãn 4 chiều vượt trội:</strong> Sự kết hợp với 16% <a href="https://www.coolmate.me/blog/spandex-la-gi" target="_blank" rel="noopener">Spandex</a> giúp giải phóng mọi chuyển động, từ những cú vung tay mạnh mẽ đến những pha di chuyển linh hoạt.</p></li><li><p><strong>Đường cắt tôn dáng công thái học:</strong> Các đường cắt ở ngực, eo và vai được nghiên cứu dựa trên chuyển động của cơ thể, vừa tôn dáng, vừa mang lại sự thoải mái.</p></li><li><p><strong>Bốn lựa chọn màu sắc cá tính:</strong> Các phiên bản <strong>Trắng, Đen, Đỏ, Navy</strong> mang đến những lựa chọn đa dạng, dễ dàng thể hiện phong cách riêng.</p></li></ul><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/top-ao-pickleball-nu-dep-thoai-mai" target="_blank" rel="noopener">Top Áo Pickleball Nữ: Đẹp, Thoải Mái, Nâng Tầm Phong Cách</a></p><h2 style="text-align: justify;">Hoàn Thiện Bộ Trang Phục Sân Đấu</h2><p style="text-align: justify;">Với thiết kế đặc trưng, chiếc áo này là lựa chọn hoàn hảo để bạn nâng tầm phong cách:</p><ul><li><p><strong>Set đồ chuyên nghiệp:</strong> Hãy kết hợp cùng một chiếc <a href="https://www.coolmate.me/collection/quan-nu-pickleball" target="_blank" rel="noopener">quần pickleball nữ</a> hoặc một chiếc <a href="https://www.coolmate.me/collection/vay-dam-nu-pickleball" target="_blank" rel="noopener">váy pickleball nữ</a> để tạo nên một bộ <a href="https://www.coolmate.me/collection/quan-ao-pickleball-nu" target="_blank" rel="noopener">quần áo pickleball nữ</a> đầy phong cách.</p></li><li><p><strong>Hoàn thiện trang bị:</strong> Đừng quên những chi tiết nhỏ, hãy kết hợp thêm <a href="https://www.coolmate.me/collection/tat-vo-nu-pickleball" target="_blank" rel="noopener">tất pickleball nữ</a> và các <a href="https://www.coolmate.me/collection/phu-kien-nu-pickleball" target="_blank" rel="noopener">phụ kiện pickleball nữ</a> chuyên dụng khác để có một vẻ ngoài hoàn hảo nhất.</p></li></ul><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/choi-pickleball-mac-gi-4464" target="_blank" rel="noopener">Chơi Pickleball Mặc Đồ Gì? Chọn &amp; Phối Đồ Chuẩn Coolmate</a></p><h2 style="text-align: justify;">Bí Quyết Giữ Gìn Hiệu Năng</h2><p style="text-align: justify;">Để bảo vệ các tính năng kỹ thuật của sản phẩm, bạn hãy lưu ý những điều sau:</p><ul><li><p>Luôn lộn trái áo trước khi giặt để bảo vệ các chi tiết in và bề mặt vải.</p></li><li><p>Giặt máy ở nhiệt độ nước không quá 40°C và tránh sử dụng các chất tẩy rửa mạnh.</p></li><li><p>Tránh dùng nước xả vải vì có thể làm giảm hiệu quả thấm hút của công nghệ ExDry.</p></li></ul><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/giat-quan-ao-the-thao-nam-giup-quan-ao-luon-nhu-moi" target="_blank" rel="noopener">Cách Giặt Quần Áo Thể Thao: Bền Màu, Không Hôi, Đúng Cách</a></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 259000.00, null, true, null, '2026-07-01 14:39:05', '2026-07-01 14:39:05');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (18, 22, 'Áo Croptop Pickleball Volley Essentials', 'ao-croptop-pickleball-volley-essentials', 'Kết hợp giữa Polyester tái chế và Spandex, chất vải vừa thấm hút nhanh, khô thoáng tức thì và co giãn linh hoạt', '<p></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 259000.00, null, true, null, '2026-07-01 14:42:54', '2026-07-01 14:42:54');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (19, 22, 'Croptop thể thao Vital Seamless - Đen', 'croptop-the-thao-vital-seamless-den', 'Công nghệ seamless hạn chế tối đa đường may, giúp áo ôm sát cơ thể tự nhiên, co giãn đa chiều và theo sát từng chuyển động', '<h2 style="text-align: center;">Croptop thể thao Vital Seamless - Hiệu Suất Tối Ưu, Tôn Dáng Hoàn Hảo</h2><p style="text-align: justify;">Nâng tầm trải nghiệm tập luyện của bạn với Croptop thể thao Vital Seamless, một mảnh ghép không thể thiếu trong bộ sưu tập <a href="https://www.coolmate.me/collection/vital-seamless" target="_blank" rel="noopener">quần áo vital seamless</a> của phái đẹp. Được thiết kế như một chiếc <a href="https://www.coolmate.me/collection/ao-cropped-top" target="_blank" rel="noopener">áo croptop nữ</a> hiệu suất cao, sản phẩm này ứng dụng công nghệ dệt seamless (không đường may) tiên tiến, giảm tối đa ma sát để bạn hoàn toàn tập trung vào từng chuyển động. Sự pha trộn chiến lược giữa 52% Nylon, 43% <a href="https://www.coolmate.me/post/vai-polyester-la-gi" target="_blank" rel="noopener">vải polyester</a> và 5% <a href="https://www.coolmate.me/post/spandex-la-gi" target="_blank" rel="noopener">vải spandex</a> tạo nên một chất liệu co giãn bốn chiều, ôm sát cơ thể như lớp da thứ hai. Công nghệ Ex-Dry tích hợp giúp thấm hút mồ hôi và làm khô nhanh chóng, giữ cho bạn luôn cảm thấy thoáng mát và tự tin, biến đây thành lựa chọn ưu việt trong dòng <a href="https://www.coolmate.me/collection/ao-nu" target="_blank" rel="noopener">áo nữ</a> thể thao.</p><h2 style="text-align: justify;">Thiết Kế Seamless Thông Minh Và Tôn Dáng</h2><p style="text-align: justify;">Mỗi chi tiết trên chiếc <a href="https://www.coolmate.me/collection/ao-nu-choi-the-thao" target="_blank" rel="noopener">áo thể thao nữ</a> này đều được tính toán kỹ lưỡng để hỗ trợ và tôn lên vóc dáng người mặc. Áo sở hữu phom dáng Tight fit, ôm sát nhưng vẫn đảm bảo sự thoải mái tuyệt đối.</p><ul><li><p><strong>Công nghệ Seamless:</strong> Hạn chế tối đa đường may, loại bỏ cảm giác cộm, ngứa hay ma sát khó chịu.</p></li><li><p><strong>Thiết kế contouring:</strong> Các đường dệt định hình vùng ngực và eo giúp giữ form áo, tôn dáng tự nhiên mà vẫn duy trì sự thoải mái trong các bài tập cường độ cao.</p></li><li><p><strong>Thoáng khí tối ưu:</strong> Các vùng dệt lưới được bố trí thông minh để tăng cường khả năng thoát ẩm, kiểm soát mồ hôi hiệu quả.</p></li></ul><p style="text-align: justify;"><em>Thông tin người mẫu: Mẫu cao 1m65, nặng 50kg, số đo 80-63-92(cm) - Mặc Size M.</em></p><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/bi-quyet-chon-size-ao-croptop-nu-chuan-xac-tu-tin-khoe-ca-tinh-5664" target="_blank" rel="noopener">Bí quyết chọn size áo croptop nữ chuẩn xác, tự tin khoe cá tính</a></p><h2 style="text-align: justify;">Linh Hoạt Trong Mọi Hoạt Động Thể Chất</h2><p style="text-align: justify;">Chiếc áo croptop này là người bạn đồng hành lý tưởng cho đa dạng các bộ môn và hoạt động:</p><ul><li><p>Tập luyện trong phòng gym, các lớp Yoga và Pilates.</p></li><li><p>Các hoạt động ngoài trời như đi bộ, chạy bộ nhẹ nhàng.</p></li><li><p>Phối đồ hàng ngày cho phong cách athleisure năng động.</p></li></ul><p style="text-align: justify;">Để có một bộ <a href="https://www.coolmate.me/collection/coolmate-activewear-nu" target="_blank" rel="noopener">đồ thể thao nữ</a> hoàn chỉnh, hãy kết hợp áo với <a href="https://www.coolmate.me/collection/quan-short-nu" target="_blank" rel="noopener">quần short nữ</a> hoặc legging, tạo nên một set <a href="https://www.coolmate.me/collection/quan-ao-chay-bo" target="_blank" rel="noopener">quần áo chạy bộ nữ</a> đầy phong cách và chuyên nghiệp.</p><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/10-bi-kip-phoi-do-voi-ao-croptop-tu-tin-khoe-dang-bung-xoa-het-minh-5631" target="_blank" rel="noopener">10 Cách Phối Đồ Với Áo Croptop Chuẩn Trend Cho Nàng</a></p><h2 style="text-align: justify;">Bí Quyết Giữ Sản Phẩm Bền Đẹp</h2><p style="text-align: justify;">Để sản phẩm luôn giữ được độ co giãn và phom dáng tốt nhất, bạn hãy lưu ý:</p><ul><li><p>Giặt máy bằng nước lạnh với chế độ giặt nhẹ và sử dụng túi giặt.</p></li><li><p>Không sử dụng thuốc tẩy hoặc các chất làm mềm vải.</p></li><li><p>Phơi ở nơi thoáng mát, tránh ánh nắng trực tiếp để bảo vệ cấu trúc sợi vải.</p></li></ul><p style="text-align: justify;">Việc tuân thủ hướng dẫn sẽ giúp sản phẩm bền đẹp hơn. Bạn có thể tìm hiểu thêm về <a href="https://www.coolmate.me/post/bao-quan-va-giat-ao-croptop-chuan-chinh-tu-a-z-5641" target="_blank" rel="noopener">cách bảo quản và giặt áo croptop</a> để chăm sóc tốt nhất cho trang phục của mình.</p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 289000.00, 173000.00, true, null, '2026-07-01 14:44:58', '2026-07-01 14:44:58');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (20, 22, 'Croptop dài tay thể thao Vital Seamless - Hồng', 'croptop-dai-tay-the-thao-vital-seamless-hong', 'Công nghệ seamless hạn chế tối đa đường may, giúp áo ôm sát cơ thể tự nhiên, co giãn đa chiều và theo sát từng chuyển động', '<h2 style="text-align: center;">Croptop Dài Tay Thể Thao Vital Seamless - Nâng Tầm Trải Nghiệm Luyện Tập</h2><p style="text-align: justify;">Nâng cao hiệu suất và sự tự tin trong mỗi buổi tập với Áo Croptop dài tay thể thao Vital Seamless, một mảnh ghép <a href="https://www.coolmate.me/collection/ao-dai-tay-nu" target="_blank" rel="noopener">áo dài tay nữ</a> không thể thiếu trong bộ sưu tập <a href="https://www.coolmate.me/collection/coolmate-activewear-nu" target="_blank" rel="noopener">đồ thể thao nữ</a> của mọi cô gái. Đây là lựa chọn lý tưởng cho những ai yêu thích các bộ môn như Yoga&amp;Pilates hay Gym, thuộc dòng sản phẩm <a href="https://www.coolmate.me/collection/vital-seamless" target="_blank" rel="noopener">quần áo vital seamless</a> chuyên dụng. Mẫu <a href="https://www.coolmate.me/collection/ao-cropped-top" target="_blank" rel="noopener">áo croptop</a> này là sự kết hợp hoàn hảo của 52% Nylon, 43% <a href="https://www.coolmate.me/blog/vai-polyester-la-gi" target="_blank" rel="noopener">vải polyester</a> và 5% <a href="https://www.coolmate.me/blog/spandex-la-gi" target="_blank" rel="noopener">vải spandex</a>, tạo nên một chất liệu bền bỉ, nhanh khô và co giãn bốn chiều vượt trội. Công nghệ Ex-Dry tích hợp giúp chiếc <a href="https://www.coolmate.me/collection/ao-nu" target="_blank" rel="noopener">áo nữ</a> thấm hút mồ hôi tức thì, giữ cho cơ thể bạn luôn khô ráo và thoáng mát. Công nghệ dệt seamless hạn chế tối đa đường may, mang lại cảm giác thoải mái tuyệt đối, giúp bạn hoàn toàn tập trung vào từng chuyển động mà không bị phân tâm. Đây là một phần của bộ sưu tập <a href="https://www.coolmate.me/collection/do-thu-dong" target="_blank" rel="noopener">quần áo thu đông</a> của Coolmate.</p><h2 style="text-align: justify;">Thiết Kế Tôn Dáng, Tối Ưu Từng Chuyển Động</h2><p style="text-align: justify;">Chiếc <a href="https://www.coolmate.me/collection/ao-nu-choi-the-thao" target="_blank" rel="noopener">áo thể thao nữ</a> này sở hữu kiểu dáng Tight fit ôm sát cơ thể, không chỉ giúp tôn lên những đường cong quyến rũ mà còn hỗ trợ tối ưu cho các nhóm cơ khi vận động. Mọi chi tiết đều được thiết kế để mang lại sự thoải mái và hiệu quả cao nhất.</p><ul><li><p><strong>Công nghệ dệt seamless: </strong>Giảm thiểu ma sát trên da, mang lại trải nghiệm &quot;mặc như không mặc&quot;.</p></li><li><p><strong>Thiết kế tôn dáng:</strong> Dáng áo croptop kết hợp với các đường nét định hình ở ngực và eo giúp giữ form, tạo nên vóc dáng cân đối.</p></li><li><p><strong>Tối ưu thoáng khí:</strong> Các vùng dệt với kết cấu khác nhau được bố trí thông minh tại các điểm thoát mồ hôi nhiều như ngực và lưng, giúp điều hòa thân nhiệt hiệu quả.</p></li></ul><p style="text-align: justify;"><em>Thông tin người mẫu: Mẫu cao 1m65, nặng 50kg, số đo 80-63-92(cm) - mặc Size M.</em></p><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/bi-quyet-chon-size-ao-croptop-nu-chuan-xac-tu-tin-khoe-ca-tinh-5664" target="_blank" rel="noopener">Bí quyết chọn size áo croptop nữ chuẩn xác, tự tin khoe cá tính</a></p><h2 style="text-align: justify;">Đồng Hành Cùng Bạn Trong Mọi Buổi Tập</h2><p style="text-align: justify;">Với tính linh hoạt và thiết kế thông minh, Áo Croptop Vital Seamless là chiếc <a href="https://www.coolmate.me/collection/ao-thun-nu" target="_blank" rel="noopener" class="in-cell-link">áo thun nữ</a> lý tưởng cho nhiều hoạt động thể chất:</p><ul><li><p>Hoàn hảo cho các bộ môn đòi hỏi sự dẻo dai như Yoga và Pilates.</p></li><li><p>Phù hợp cho các buổi tập gym, cardio hay các hoạt động ngoài trời như đi bộ, đây là chiếc <a href="https://www.coolmate.me/collection/ao-nu-tap-gym" target="_blank" rel="noopener">áo tập gym nữ</a> lý tưởng cho bạn.</p></li></ul><p style="text-align: justify;">Để có một bộ <a href="https://www.coolmate.me/collection/quan-ao-phu-kien-tap-gym-nu" target="_blank" rel="noopener">đồ tập gym nữ</a> hoàn chỉnh, bạn có thể kết hợp áo cùng một chiếc <a href="https://www.coolmate.me/collection/quan-legging" target="_blank" rel="noopener">quần legging</a>, <a href="https://www.coolmate.me/collection/quan-nu-tap-gym" target="_blank" rel="noopener">quần tập gym nữ</a> co giãn hoặc một chiếc <a href="https://www.coolmate.me/collection/quan-short-nu" target="_blank" rel="noopener">quần short nữ</a> năng động, phối với <a href="https://www.coolmate.me/collection/ao-khoac-nu" target="_blank" rel="noopener">áo khoác nữ</a> khoác ngoài, và đừng quên các loại <a href="https://www.coolmate.me/collection/phu-kien-nu-tap-gym" target="_blank" rel="noopener">phụ kiện gym nữ</a> chuyên dụng.</p><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm: </strong><a href="https://www.coolmate.me/post/10-bi-kip-phoi-do-voi-ao-croptop-tu-tin-khoe-dang-bung-xoa-het-minh-5631" target="_blank" rel="noopener">10 Cách Phối Đồ Với Áo Croptop Chuẩn Trend Cho Nàng</a></p><h2 style="text-align: justify;">Bí Quyết Giữ Sản Phẩm Bền Đẹp</h2><p style="text-align: justify;">Để duy trì độ co giãn và màu sắc của sản phẩm, hãy lưu ý những mẹo bảo quản sau:</p><ul><li><p>Giặt ở nhiệt độ thường với chu kỳ máy giặt nhẹ nhàng.</p></li><li><p>Không sử dụng hóa chất tẩy rửa mạnh để tránh làm hỏng cấu trúc sợi vải.</p></li><li><p>Lộn trái sản phẩm khi phơi và tránh phơi trực tiếp dưới ánh nắng mặt trời gay gắt.</p></li></ul><p style="text-align: justify;">Áp dụng những phương pháp này sẽ giúp sản phẩm của bạn luôn bền đẹp. Bạn có thể tìm hiểu thêm về <a href="https://www.coolmate.me/post/bao-quan-va-giat-ao-croptop-chuan-chinh-tu-a-z-5641" target="_blank" rel="noopener">cách bảo quản và giặt áo croptop</a> để giữ cho trang phục yêu thích của mình luôn như mới.</p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 379000.00, null, true, null, '2026-07-01 14:47:17', '2026-07-01 14:47:17');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (21, 22, 'Croptop thể thao Vital Seamless - Hồng', 'croptop-the-thao-vital-seamless-hong', 'Vải siêu nhẹ, co giãn 4 chiều, mềm mại, thoáng khí, hỗ trợ vận động và giảm tích tụ nhiệt', '<h2 style="text-align: center;">Croptop thể thao Vital Seamless - Hiệu Suất Tối Ưu, Tôn Dáng Hoàn Hảo</h2><p>Nâng tầm trải nghiệm tập luyện của bạn với Croptop thể thao Vital Seamless, một mảnh ghép không thể thiếu trong bộ sưu tập <a href="https://www.coolmate.me/collection/vital-seamless" target="_blank" rel="noopener">quần áo vital seamless</a> của phái đẹp. Được thiết kế như một chiếc <a href="https://www.coolmate.me/collection/ao-croptop-nu" target="_blank" rel="noopener">áo croptop nữ</a> hiệu suất cao, sản phẩm này ứng dụng công nghệ dệt seamless (không đường may) tiên tiến, giảm tối đa ma sát để bạn hoàn toàn tập trung vào từng chuyển động. Sự pha trộn chiến lược giữa 52% Nylon, 43% <a href="https://www.coolmate.me/post/vai-polyester-la-gi" target="_blank" rel="noopener">vải polyester</a> và 5% <a href="https://www.coolmate.me/post/spandex-la-gi" target="_blank" rel="noopener">vải spandex</a> tạo nên một chất liệu co giãn bốn chiều, ôm sát cơ thể như lớp da thứ hai. Công nghệ Ex-Dry tích hợp giúp thấm hút mồ hôi và làm khô nhanh chóng, giữ cho bạn luôn cảm thấy thoáng mát và tự tin, biến đây thành lựa chọn ưu việt trong dòng <a href="https://www.coolmate.me/collection/ao-nu" target="_blank" rel="noopener">áo nữ</a> thể thao.</p><h2>Thiết Kế Seamless Thông Minh Và Tôn Dáng</h2><p>Mỗi chi tiết trên chiếc <a href="https://www.coolmate.me/collection/ao-nu-choi-the-thao" target="_blank" rel="noopener">áo thể thao nữ</a> này đều được tính toán kỹ lưỡng để hỗ trợ và tôn lên vóc dáng người mặc. Áo sở hữu phom dáng Tight fit, ôm sát nhưng vẫn đảm bảo sự thoải mái tuyệt đối.</p><ul><li><p><strong>Công nghệ Seamless:</strong> Hạn chế tối đa đường may, loại bỏ cảm giác cộm, ngứa hay ma sát khó chịu.</p></li><li><p><strong>Thiết kế contouring:</strong> Các đường dệt định hình vùng ngực và eo giúp giữ form áo, tôn dáng tự nhiên mà vẫn duy trì sự thoải mái trong các bài tập cường độ cao.</p></li><li><p><strong>Thoáng khí tối ưu:</strong> Các vùng dệt lưới được bố trí thông minh để tăng cường khả năng thoát ẩm, kiểm soát mồ hôi hiệu quả.</p></li></ul><p><em>Thông tin người mẫu: Mẫu cao 1m65, nặng 50kg, số đo 80-63-92(cm) - Mặc Size M.</em></p><p><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/bi-quyet-chon-size-ao-croptop-nu-chuan-xac-tu-tin-khoe-ca-tinh-5664" target="_blank" rel="noopener">Bí quyết chọn size áo croptop nữ chuẩn xác, tự tin khoe cá tính</a></p><h2>Linh Hoạt Trong Mọi Hoạt Động Thể Chất</h2><p>Chiếc áo croptop này là người bạn đồng hành lý tưởng cho đa dạng các bộ môn và hoạt động:</p><ul><li><p>Tập luyện trong phòng gym, các lớp Yoga và Pilates.</p></li><li><p>Các hoạt động ngoài trời như đi bộ, chạy bộ nhẹ nhàng.</p></li><li><p>Phối đồ hàng ngày cho phong cách athleisure năng động.</p></li></ul><p>Để có một bộ <a href="https://www.coolmate.me/collection/coolmate-activewear-nu" target="_blank" rel="noopener">đồ thể thao nữ</a> hoàn chỉnh, hãy kết hợp áo với <a href="https://www.coolmate.me/collection/quan-short-nu" target="_blank" rel="noopener">quần short nữ</a> hoặc legging, tạo nên một set <a href="https://www.coolmate.me/collection/quan-ao-chay-bo" target="_blank" rel="noopener">quần áo chạy bộ nữ</a> đầy phong cách và chuyên nghiệp.</p><p><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/post/10-bi-kip-phoi-do-voi-ao-croptop-tu-tin-khoe-dang-bung-xoa-het-minh-5631" target="_blank" rel="noopener">10 Cách Phối Đồ Với Áo Croptop Chuẩn Trend Cho Nàng</a></p><h2>Bí Quyết Giữ Sản Phẩm Bền Đẹp</h2><p>Để sản phẩm luôn giữ được độ co giãn và phom dáng tốt nhất, bạn hãy lưu ý:</p><ul><li><p>Giặt máy bằng nước lạnh với chế độ giặt nhẹ và sử dụng túi giặt.</p></li><li><p>Không sử dụng thuốc tẩy hoặc các chất làm mềm vải.</p></li><li><p>Phơi ở nơi thoáng mát, tránh ánh nắng trực tiếp để bảo vệ cấu trúc sợi vải.</p></li></ul><p>Việc tuân thủ hướng dẫn sẽ giúp sản phẩm bền đẹp hơn. Bạn có thể tìm hiểu thêm về <a href="https://www.coolmate.me/post/bao-quan-va-giat-ao-croptop-chuan-chinh-tu-a-z-5641" target="_blank" rel="noopener">cách bảo quản và giặt áo croptop</a> để chăm sóc tốt nhất cho trang phục của mình.</p>', '{"Phù hợp": "Mặc hàng ngày, chơi thể thao các môn cường độ nhẹ như Yoga & Pillates, Gym, Đi bộ", "Tính năng": "Thấm hút và nhanh khô", "Bảo quản": "Giặt máy nhẹ - Sấy ở mức nhiệt thấp  Không dùng chất tẩy - Không giặt khô  *", "Công nghệ": "Ex-Dry", "Kiểu dáng": "Tight fit  Mẫu cao 1m65, nặng 50kg, 80-63-92(cm) - Size M", "Chất liệu": "52% Nylon 43% Polyester 5% Spandex"}', 289000.00, null, true, null, '2026-07-01 14:49:49', '2026-07-01 14:49:49');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (22, 22, 'Áo Polo nữ Pickleball Baseline', 'ao-polo-nu-pickleball-baseline', 'Chất vải đậm chất thể thao với khả năng thấm hút nhanh, khô thoáng tức thì và co giãn linh hoạt', '<h2 style="text-align: center;">Áo Polo Nữ Pickleball Baseline - Tôn Dáng Hoàn Hảo, Tự Tin Vận Động</h2><p style="text-align: justify;">Là một item không thể thiếu trong bộ sưu tập <a href="https://www.coolmate.me/collection/pickleball-tennis" target="_blank" rel="noopener">quần áo pickleball</a> của phái nữ, <strong>Áo Polo Nữ Pickleball Baseline</strong> là mẫu <a href="https://www.coolmate.me/collection/ao-nu-pickleball" target="_blank" rel="noopener">áo pickleball nữ</a> được thiết kế để tôn vinh vóc dáng và mang lại sự tự tin cho phái nữ trên sân đấu. Sản phẩm là sự kết hợp giữa 89% <a href="https://www.coolmate.me/blog/vai-polyester-la-gi" target="_blank" rel="noopener">Polyester</a> và 11% <a href="https://www.coolmate.me/blog/spandex-la-gi" target="_blank" rel="noopener">Spandex</a>, ứng dụng công nghệ <a href="https://www.coolmate.me/blog/cong-nghe-exdry-4439" target="_blank" rel="noopener">Ex-Dry</a> giúp thấm hút và làm khô mồ hôi nhanh chóng. Mẫu <a href="https://www.coolmate.me/collection/ao-cropped-top" target="_blank" rel="noopener">áo croptop nữ</a> này sử dụng chất vải cao cấp với độ co giãn tốt và có khả năng thoáng khí (Breathable), đảm bảo bạn luôn cảm thấy dễ chịu ngay cả khi vận động liên tục. Cảm nhận thực tế khi mặc là chất vải nhẹ, mềm mại ôm vừa vặn theo đường cong cơ thể nhưng không hề gò bó, mang lại cảm giác thoải mái và phong thái tự tin suốt cả trận đấu.</p><h2 style="text-align: justify;">Thiết Kế Slim Fit &amp; Đệm Ngực Cố Định Tiện Lợi</h2><p style="text-align: justify;">Áo sở hữu dáng <a href="https://www.coolmate.me/blog/slim-fit-la-gi-cach-dien-ao-thun-slim-fit-ton-body-471" target="_blank" rel="noopener">Slim Fit</a> với cổ polo cách điệu dáng V, tạo nên một tổng thể vừa nữ tính, hiện đại, vừa năng động, khỏe khoắn.</p><ul><li><p><strong>Đường cắt tôn dáng:</strong> Các đường cắt được tính toán kỹ lưỡng để ôm theo đường cong cơ thể, tạo hiệu ứng thị giác thon gọn và thanh lịch.</p></li><li><p><strong>Miếng đệm liền ngực:</strong> Chi tiết quan trọng giúp cố định và hỗ trợ vòng một khi vận động, mang lại sự tự tin mà không cần mặc thêm bra thể thao.</p></li><li><p><strong>Form tanktop năng động:</strong> Dễ dàng vận động và khoe trọn vẻ đẹp khỏe khoắn của đôi vai.</p></li><li><p><strong>Nhãn Silicone cao cấp:</strong> Tạo điểm nhấn nhận diện thương hiệu một cách tinh tế.</p></li></ul><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/bi-quyet-chon-size-ao-croptop-nu-chuan-xac-tu-tin-khoe-ca-tinh-5664" target="_blank" rel="noopener">Bí Quyết Chọn Size Áo Croptop Nữ Chuẩn Xác – Tự Tin Khoe Cá Tính</a></p><h2 style="text-align: justify;">Phong Cách Đa Năng Từ Sân Đấu Đến Đời Thường</h2><p style="text-align: justify;">Là một thiết kế nổi bật trong Bộ sưu tập <a href="https://www.coolmate.me/collection/pickleball-tennis-cho-nu" target="_blank" rel="noopener">Quần áo Pickleball nữ</a> Coolmate, chiếc áo polo này giúp các nàng dễ dàng ứng dụng trong nhiều hoàn cảnh khác nhau.</p><ul><li><p><strong>Trên sân đấu:</strong> Là lựa chọn hoàn hảo cho các buổi tập luyện hoặc thi đấu Pickleball, mang lại sự tự tin và phong thái chuyên nghiệp.</p></li><li><p><strong>Phong cách hàng ngày:</strong> Kết hợp cực kỳ ăn ý với <a href="https://www.coolmate.me/collection/vay-dam-nu-pickleball" target="_blank" rel="noopener">chân váy pickleball</a>, <a href="https://www.coolmate.me/collection/quan-short-nu" target="_blank" rel="noopener">quần Shorts nữ</a>, đặc biệt là khi phối cùng <a href="https://www.coolmate.me/product/vay-pickleball-baseline" target="_blank" rel="noopener">Váy Pickleball Baseline</a> để tạo nên một set đồ thể thao thời thượng.</p></li></ul><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/choi-pickleball-mac-gi-4464" target="_blank" rel="noopener">Chơi Pickleball mặc gì? Top 4 cách phối đồ chơi Pickleball cực chất</a></p><h2 style="text-align: justify;">Bí Quyết Giữ Sản Phẩm Bền Đẹp</h2><ul><li><p>Để chiếc <a href="https://www.coolmate.me/collection/ao-nu-choi-the-thao" target="_blank" rel="noopener">áo thể thao nữ</a> yêu thích của bạn luôn giữ được form dáng, hãy giặt ngay sau mỗi lần tập luyện.</p></li><li><p>Hãy hạn chế sử dụng nước xả vải vì chúng có thể làm giảm hiệu quả của công nghệ Ex-Dry và ảnh hưởng đến độ co giãn của vải.</p></li><li><p>Ưu tiên giặt tay hoặc dùng túi giặt ở chế độ nhẹ để bảo vệ cấu trúc áo và phần miếng đệm ngực liền một cách tốt nhất.</p></li></ul><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/mach-nang-cach-cham-soc-quan-ao-the-thao-dung-cach-ben-dep-nhu-moi-5200" target="_blank" rel="noopener">Mách nàng cách chăm sóc quần áo thể thao đúng cách, bền đẹp như mới</a></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 449000.00, null, true, null, '2026-07-01 14:53:28', '2026-07-01 14:53:28');
INSERT INTO shopwise_db.products (id, category_id, name, slug, headline, description, additional_info, price, sale_price, is_active, deleted_at, created_at, updated_at) VALUES (23, 22, 'Áo Crop top nữ Pickleball Dink Shot', 'ao-crop-top-nu-pickleball-dink-shot', 'Kết hợp giữa Polyester tái chế và Spandex, chất vải vừa thấm hút nhanh, khô thoáng tức thì và co giãn linh hoạt', '<h2 style="text-align: center;">Áo Crop top nữ Pickleball Dink Shot - Thoáng Mát Và Co Giãn Vượt Trội</h2><p style="text-align: justify;">Là một mảnh ghép phong cách và không thể thiếu trong tủ <a href="https://www.coolmate.me/collection/pickleball-tennis" target="_blank" rel="noopener">quần áo pickleball</a> của bạn, <strong>Áo Crop top nữ Pickleball Dink Shot</strong> là lựa chọn hoàn hảo để bạn tự tin làm chủ mọi trận đấu, mang đến sự thoải mái trong từng cú đánh. Mẫu <a href="https://www.coolmate.me/collection/ao-nu-pickleball" target="_blank" rel="noopener">áo pickleball nữ</a> này là sự kết hợp tối ưu giữa 86% <a href="https://www.coolmate.me/post/vai-recycle-la-gi-1668" target="_blank" rel="noopener">Recycled Polyester</a> và 14% <a href="https://www.coolmate.me/post/spandex-la-gi-elastane-la-gi-tai-sao-luon-co-thanh-phan-nay-trong-may-mac" target="_blank" rel="noopener">Spandex</a>, không chỉ thân thiện với môi trường mà còn tạo nên bề mặt vải siêu nhẹ và co giãn 4 chiều linh hoạt. Đặc biệt, <a href="https://www.coolmate.me/post/cong-nghe-exdry-4439" target="_blank" rel="noopener">công nghệ Ex-Dry</a> được tích hợp giúp <a href="https://www.coolmate.me/collection/ao-cropped-top" target="_blank" rel="noopener">áo croptop</a> thấm hút mồ hôi gần như ngay lập tức và bay hơi nhanh chóng, giữ cho cơ thể luôn khô thoáng và mát mẻ. Khi chạm vào, bạn sẽ cảm nhận ngay chất vải mềm mại, không gây bí bách, giúp bạn hoàn toàn tập trung vào trận đấu mà vẫn giữ được form dáng chuẩn sau nhiều lần vận động.</p><h2 style="text-align: justify;">Thiết Kế Crop Top Năng Động Và Tinh Tế</h2><p style="text-align: justify;">Áo sở hữu kiểu dáng croptop regular fit gọn gàng, vừa vặn, không chỉ khéo léo tôn lên vòng eo mà còn đảm bảo sự linh hoạt tối đa cho mọi động tác vung vợt và di chuyển trên sân.</p><ul><li><p><strong>Cổ bo dệt tinh tế:</strong> Phần cổ áo được dệt bo với đường viền màu sắc nổi bật, tạo điểm nhấn thời trang và cá tính.</p></li><li><p><strong>Dấu ấn Pickleball: </strong>Logo silicone &quot;COOLMATE PICKLEBALL&quot; được in sắc nét trên ngực, thể hiện rõ tinh thần thể thao và niềm đam mê với bộ môn.</p></li></ul><p style="text-align: justify;"><em>Mẫu cao 1m65, nặng 50kg, số đo 80-63-92(cm) - Mặc size M.</em></p><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/bi-quyet-chon-size-ao-thun-nu-chuan-nhu-may-do-568" target="_blank" rel="noopener">Bí quyết chọn size áo thun nữ chuẩn như may đo</a></p><h2 style="text-align: justify;">Linh Hoạt Trên Sân, Phong Cách Đời Thường</h2><ul><li><p><strong>Chơi Pickleball:</strong> Khi kết hợp cùng quần short hoặc <a href="https://www.coolmate.me/collection/vay-dam-nu-pickleball" target="_blank" rel="noopener">váy pickleball nữ</a>, mẫu áo này sẽ tạo nên một bộ trang phục thi đấu vừa thoải mái vừa phong cách.</p></li><li><p><strong>Các môn thể thao khác:</strong> Là lựa chọn tuyệt vời cho các buổi tập gym, tennis, cầu lông hay chạy bộ.</p></li><li><p><strong>Mặc hàng ngày:</strong> Dễ dàng kết hợp cùng chân váy tennis hoặc các loại <a href="https://www.coolmate.me/collection/pickleball-tennis-cho-nu" target="_blank" rel="noopener">set đồ pickleball nữ</a> khác để tạo nên một set đồ dạo phố khỏe khoắn, năng động.</p></li></ul><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/10-bi-kip-phoi-do-voi-ao-croptop-tu-tin-khoe-dang-bung-xoa-het-minh-5631" target="_blank" rel="noopener">10 Bí Kíp Phối Đồ Với Áo Croptop: Tự Tin Khoe Dáng &amp; Bung Xõa Hết Mình</a></p><h2 style="text-align: justify;">Bí Quyết Giữ Sản Phẩm Bền Đẹp</h2><p style="text-align: justify;">Để chiếc áo crop top của bạn luôn thơm tho, hãy giặt ngay sau mỗi buổi tập để loại bỏ mồ hôi và vi khuẩn tích tụ.</p><p style="text-align: justify;">Tuyệt đối không dùng nước xả vải vì chúng có thể làm giảm khả năng thấm hút và thoát ẩm của công nghệ Ex-Dry trên áo.</p><p style="text-align: justify;">Hãy giặt máy ở chế độ nhẹ với nước lạnh và phơi khô tự nhiên để bảo vệ tốt nhất độ co giãn và form dáng sản phẩm.</p><p style="text-align: justify;"><strong>&gt;&gt;&gt; Xem thêm:</strong> <a href="https://www.coolmate.me/blog/mach-nang-cach-cham-soc-quan-ao-the-thao-dung-cach-ben-dep-nhu-moi-5200" target="_blank" rel="noopener">Mách nàng cách chăm sóc quần áo thể thao đúng cách, bền đẹp như mới</a></p>', '{"Phù hợp": "", "Tính năng": "", "Bảo quản": "", "Công nghệ": "", "Kiểu dáng": "", "Chất liệu": ""}', 279000.00, null, true, null, '2026-07-01 14:57:56', '2026-07-01 14:57:56');
